{
  "name": "BizFlow Pro",
  "description": "A comprehensive business management platform for managing quotations, invoices, sales, and expenses with integrated PDF generation and smart features.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DocumentType {
  QUOTATION = 'QUOTATION',
  INVOICE = 'INVOICE'
}

export enum TransactionType {
  SALE = 'SALE',
  EXPENSE = 'EXPENSE'
}

export interface BusinessDetails {
  name: string;
  email: string;
  phone: string;
  address: string;
  taxId: string;
  currency: string;
  logoUrl?: string;
}

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface Document {
  id: string;
  type: DocumentType;
  number: string;
  date: string;
  dueDate: string;
  clientName: string;
  clientEmail: string;
  items: LineItem[];
  status: 'Draft' | 'Sent' | 'Paid' | 'Expired';
  notes?: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  date: string;
  category: string;
  amount: number;
  description: string;
  reference?: string;
}

export interface AppState {
  business: BusinessDetails;
  documents: Document[];
  transactions: Transaction[];
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import Settings from './components/Settings';
import { AppState, DocumentType, TransactionType } from './types';

const INITIAL_STATE: AppState = {
  business: {
    name: 'Acme Corp',
    email: 'contact@acmecorp.com',
    phone: '+1 (555) 012-3456',
    address: '123 Business Way, Tech City, TC 90210',
    taxId: 'TX-99887766',
    currency: 'USD'
  },
  documents: [],
  transactions: []
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('bizflow_state');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  useEffect(() => {
    localStorage.setItem('bizflow_state', JSON.stringify(state));
  }, [state]);

  const updateBusiness = (business: AppState['business']) => {
    setState(prev => ({ ...prev, business }));
  };

  const addDocument = (doc: any) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
  };

  const updateDocumentStatus = (id: string, status: any) => {
      setState(prev => ({
          ...prev,
          documents: prev.documents.map(d => d.id === id ? { ...d, status } : d)
      }));
  };

  const deleteDocument = (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
  };

  const addTransaction = (tx: any) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
  };

  const deleteTransaction = (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden">
        <Sidebar />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <Routes>
            <Route path="/" element={<Dashboard state={state} />} />
            <Route 
              path="/quotations" 
              element={<DocumentManager 
                type={DocumentType.QUOTATION} 
                state={state} 
                addDocument={addDocument} 
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/invoices" 
              element={<DocumentManager 
                type={DocumentType.INVOICE} 
                state={state} 
                addDocument={addDocument} 
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/sales" 
              element={<TransactionManager 
                type={TransactionType.SALE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/expenses" 
              element={<TransactionManager 
                type={TransactionType.EXPENSE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/settings" 
              element={<Settings business={state.business} updateBusiness={updateBusiness} />} 
            />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { Link, useLocation } from 'react-router-dom';

const Sidebar: React.FC = () => {
  const location = useLocation();

  const navItems = [
    { name: 'Dashboard', icon: 'fa-chart-pie', path: '/' },
    { name: 'Quotations', icon: 'fa-file-lines', path: '/quotations' },
    { name: 'Invoices', icon: 'fa-file-invoice-dollar', path: '/invoices' },
    { name: 'Sales', icon: 'fa-money-bill-trend-up', path: '/sales' },
    { name: 'Expenses', icon: 'fa-receipt', path: '/expenses' },
    { name: 'Settings', icon: 'fa-gear', path: '/settings' },
  ];

  return (
    <aside className="w-64 bg-slate-900 text-white flex flex-col hidden md:flex">
      <div className="p-6">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg">
            <i className="fa-solid fa-bolt text-xl"></i>
          </div>
          <h1 className="text-xl font-bold tracking-tight">BizFlow Pro</h1>
        </div>
      </div>

      <nav className="flex-1 mt-4">
        <ul className="space-y-1 px-3">
          {navItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <li key={item.name}>
                <Link
                  to={item.path}
                  className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${
                    isActive 
                      ? 'bg-blue-600 text-white' 
                      : 'text-slate-400 hover:bg-slate-800 hover:text-white'
                  }`}
                >
                  <i className={`fa-solid ${item.icon} w-5`}></i>
                  <span className="font-medium">{item.name}</span>
                </Link>
              </li>
            );
          })}
        </ul>
      </nav>

      <div className="p-6 border-t border-slate-800">
        <div className="bg-slate-800 rounded-xl p-4">
          <p className="text-xs text-slate-400 font-medium uppercase mb-1">Plan</p>
          <p className="text-sm font-semibold">Business Pro</p>
          <div className="mt-3 w-full bg-slate-700 h-1.5 rounded-full overflow-hidden">
            <div className="bg-blue-500 h-full w-2/3"></div>
          </div>
          <p className="text-[10px] text-slate-400 mt-2">68% of storage used</p>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { AppState, Document, DocumentType, LineItem } from '../types';
import { generatePDF } from '../utils/pdfGenerator';
import { GoogleGenAI } from "@google/genai";

interface Props {
  type: DocumentType;
  state: AppState;
  addDocument: (doc: Document) => void;
  deleteDocument: (id: string) => void;
  updateStatus: (id: string, status: any) => void;
}

const DocumentManager: React.FC<Props> = ({ type, state, addDocument, deleteDocument, updateStatus }) => {
  const [showModal, setShowModal] = useState(false);
  const [loadingSmart, setLoadingSmart] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    notes: '',
    items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }] as LineItem[]
  });

  const filteredDocs = state.documents.filter(d => d.type === type);

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (id: string) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newDoc: Document = {
      id: Date.now().toString(),
      type,
      number: `${type === DocumentType.QUOTATION ? 'QT' : 'INV'}-${Math.floor(1000 + Math.random() * 9000)}`,
      clientName: formData.clientName,
      clientEmail: formData.clientEmail,
      date: formData.date,
      dueDate: formData.dueDate,
      items: formData.items,
      status: 'Draft',
      notes: formData.notes
    };
    addDocument(newDoc);
    setShowModal(false);
    setFormData({
      clientName: '',
      clientEmail: '',
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      notes: '',
      items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }]
    });
  };

  const handleSmartGenerate = async () => {
    setLoadingSmart(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
        const prompt = `Generate 3 professional service line items for a business in the ${state.business.name} industry. Return ONLY a JSON array of items with 'description' and a typical 'unitPrice' number.`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });
        const items = JSON.parse(response.text || '[]');
        setFormData(prev => ({
            ...prev,
            items: items.map((it: any, idx: number) => ({
                id: `smart-${idx}`,
                description: it.description,
                quantity: 1,
                unitPrice: it.unitPrice
            }))
        }));
    } catch (err) {
        console.error("AI Error:", err);
    } finally {
        setLoadingSmart(false);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">{type === DocumentType.QUOTATION ? 'Quotations' : 'Invoices'}</h1>
          <p className="text-slate-500">Manage your business documents here.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-semibold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all flex items-center gap-2"
        >
          <i className="fa-solid fa-plus"></i>
          Create {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Number</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Client</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Date</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Amount</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Status</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredDocs.length === 0 ? (
                <tr>
                    <td colSpan={6} className="px-6 py-12 text-center text-slate-400">
                        <i className="fa-solid fa-folder-open text-4xl mb-3 block"></i>
                        No records found.
                    </td>
                </tr>
            ) : filteredDocs.map(doc => {
              const total = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
              return (
                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-semibold text-slate-900">{doc.number}</td>
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-800">{doc.clientName}</div>
                    <div className="text-xs text-slate-500">{doc.clientEmail}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{doc.date}</td>
                  <td className="px-6 py-4 font-bold text-slate-900">{state.business.currency} {total.toLocaleString()}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      doc.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                      doc.status === 'Draft' ? 'bg-slate-100 text-slate-600' : 'bg-orange-100 text-orange-700'
                    }`}>
                      {doc.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button 
                        onClick={() => generatePDF(doc, state.business)}
                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                        title="Download PDF"
                    >
                      <i className="fa-solid fa-file-pdf"></i>
                    </button>
                    <button 
                        onClick={() => updateStatus(doc.id, 'Paid')}
                        className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg"
                        title="Mark as Paid"
                    >
                      <i className="fa-solid fa-check"></i>
                    </button>
                    <button 
                        onClick={() => deleteDocument(doc.id)}
                        className="p-2 text-red-600 hover:bg-red-50 rounded-lg"
                        title="Delete"
                    >
                      <i className="fa-solid fa-trash"></i>
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
              <h2 className="text-2xl font-bold text-slate-900">Create New {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}</h2>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 p-2">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Name</label>
                  <input 
                    required
                    value={formData.clientName}
                    onChange={(e) => setFormData({...formData, clientName: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
                    placeholder="Enter client's full name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Email</label>
                  <input 
                    required
                    type="email"
                    value={formData.clientEmail}
                    onChange={(e) => setFormData({...formData, clientEmail: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
                    placeholder="client@example.com"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Document Date</label>
                  <input 
                    type="date"
                    value={formData.date}
                    onChange={(e) => setFormData({...formData, date: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Due Date</label>
                  <input 
                    type="date"
                    value={formData.dueDate}
                    onChange={(e) => setFormData({...formData, dueDate: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all" 
                  />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Line Items</h3>
                    <button 
                        type="button"
                        disabled={loadingSmart}
                        onClick={handleSmartGenerate}
                        className="text-blue-600 text-sm font-semibold hover:underline flex items-center gap-1"
                    >
                        <i className={`fa-solid ${loadingSmart ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                        {loadingSmart ? 'Thinking...' : 'AI Suggest Items'}
                    </button>
                </div>

                <div className="space-y-3">
                  {formData.items.map((item, index) => (
                    <div key={item.id} className="flex gap-4 items-start bg-slate-50 p-4 rounded-xl">
                      <div className="flex-1">
                        <input 
                          placeholder="Description"
                          value={item.description}
                          onChange={(e) => handleItemChange(item.id, 'description', e.target.value)}
                          className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500" 
                        />
                      </div>
                      <div className="w-24">
                        <input 
                          type="number"
                          placeholder="Qty"
                          min="1"
                          value={item.quantity}
                          onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value))}
                          className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500" 
                        />
                      </div>
                      <div className="w-32">
                        <input 
                          type="number"
                          placeholder="Price"
                          value={item.unitPrice}
                          onChange={(e) => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value))}
                          className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500" 
                        />
                      </div>
                      <button 
                        type="button"
                        onClick={() => handleRemoveItem(item.id)}
                        className="p-2 text-slate-400 hover:text-red-500 transition-colors"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                  ))}
                </div>
                <button 
                  type="button"
                  onClick={handleAddItem}
                  className="w-full border-2 border-dashed border-slate-200 rounded-xl py-3 text-slate-500 font-medium hover:border-blue-400 hover:text-blue-500 transition-all"
                >
                  <i className="fa-solid fa-plus mr-2"></i>Add Another Item
                </button>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Notes & Terms</label>
                <textarea 
                  value={formData.notes}
                  onChange={(e) => setFormData({...formData, notes: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all min-h-[100px]" 
                  placeholder="Additional information for the client..."
                />
              </div>

              <div className="flex justify-end gap-4">
                <button 
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="px-6 py-3 border border-slate-200 rounded-xl font-semibold text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all"
                >
                  Save & Generate
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DocumentManager;

import React, { useState } from 'react';
import { AppState, Transaction, TransactionType } from '../types';

interface Props {
  type: TransactionType;
  state: AppState;
  addTransaction: (tx: Transaction) => void;
  deleteTransaction: (id: string) => void;
}

const TransactionManager: React.FC<Props> = ({ type, state, addTransaction, deleteTransaction }) => {
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    category: '',
    amount: 0,
    description: '',
    reference: ''
  });

  const filteredTransactions = state.transactions.filter(t => t.type === type);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newTx: Transaction = {
      id: Date.now().toString(),
      type,
      ...formData
    };
    addTransaction(newTx);
    setShowModal(false);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      category: '',
      amount: 0,
      description: '',
      reference: ''
    });
  };

  const categories = type === TransactionType.SALE 
    ? ['Product Sales', 'Service Fees', 'Subscription', 'Consulting', 'Other']
    : ['Rent', 'Utilities', 'Salaries', 'Software', 'Marketing', 'Supplies', 'Other'];

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">{type === TransactionType.SALE ? 'Sales Ledger' : 'Expense Tracker'}</h1>
          <p className="text-slate-500">Keep track of your {type.toLowerCase()} transactions.</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className={`px-5 py-2.5 rounded-xl font-semibold shadow-lg transition-all flex items-center gap-2 text-white ${
            type === TransactionType.SALE ? 'bg-emerald-600 shadow-emerald-100 hover:bg-emerald-700' : 'bg-red-600 shadow-red-100 hover:bg-red-700'
          }`}
        >
          <i className="fa-solid fa-plus"></i>
          Record {type === TransactionType.SALE ? 'Sale' : 'Expense'}
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Date</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Category</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Description</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Amount</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase text-right">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredTransactions.length === 0 ? (
                <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                         No transactions recorded yet.
                    </td>
                </tr>
            ) : filteredTransactions.map(tx => (
