import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Document, BusinessDetails } from '../types';

export const generatePDF = (doc: Document, business: BusinessDetails, viewMode: boolean = false) => {
  const pdf = new jsPDF();
  const margin = 20;

  // Header
  pdf.setFontSize(22);
  pdf.setTextColor(40, 40, 40);
  pdf.text(business.name, margin, margin + 5);

  pdf.setFontSize(10);
  pdf.setTextColor(100, 100, 100);
  pdf.text(business.address, margin, margin + 12);
  pdf.text(`${business.email} | ${business.phone}`, margin, margin + 17);
  pdf.text(`Tax ID: ${business.taxId}`, margin, margin + 22);

  // Document Title
  pdf.setFontSize(18);
  pdf.setTextColor(37, 99, 235); // Blue-600
  pdf.text(doc.type, 140, margin + 5);

  pdf.setFontSize(10);
  pdf.setTextColor(40, 40, 40);
  pdf.text(`Number: ${doc.number}`, 140, margin + 12);
  pdf.text(`Date: ${doc.date}`, 140, margin + 17);
  pdf.text(`Due Date: ${doc.dueDate}`, 140, margin + 22);

  // Client Info
  pdf.setFontSize(12);
  pdf.text('Bill To:', margin, margin + 45);
  pdf.setFontSize(11);
  pdf.setFont('helvetica', 'bold');
  pdf.text(doc.clientName, margin, margin + 52);
  pdf.setFont('helvetica', 'normal');
  pdf.text(doc.clientEmail, margin, margin + 57);

  // Table Data
  const tableHeaders = [['Description', 'Qty', 'Unit Price', 'Total']];
  const tableData = doc.items.map(item => [
    item.description,
    item.quantity.toString(),
    `${business.currency} ${item.unitPrice.toLocaleString()}`,
    `${business.currency} ${(item.quantity * item.unitPrice).toLocaleString()}`
  ]);

  const total = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);

  // Use the autoTable function directly instead of the prototype method
  autoTable(pdf, {
    startY: margin + 65,
    head: tableHeaders,
    body: tableData,
    theme: 'grid',
    headStyles: { fillColor: [37, 99, 235] },
    margin: { left: margin, right: margin },
    didDrawPage: (data) => {
      // Logic for footer on every page if needed
    }
  });

  // Get the vertical position after the table
  const finalY = (pdf as any).lastAutoTable?.finalY || 150;

  // Summary
  pdf.setFontSize(12);
  pdf.setFont('helvetica', 'bold');
  pdf.setTextColor(40, 40, 40);
  pdf.text('Total Amount:', 140, finalY + 15);
  pdf.setFontSize(14);
  pdf.setTextColor(0, 0, 0);
  pdf.text(`${business.currency} ${total.toLocaleString()}`, 140, finalY + 22);

  // Notes
  if (doc.notes) {
    pdf.setFontSize(10);
    pdf.setTextColor(100, 100, 100);
    pdf.text('Notes & Terms:', margin, finalY + 15);
    pdf.setFontSize(9);
    const splitNotes = pdf.splitTextToSize(doc.notes, 100);
    pdf.text(splitNotes, margin, finalY + 22);
  }

  // Footer
  pdf.setFontSize(8);
  pdf.setTextColor(150, 150, 150);
  pdf.text('Generated via BizFlow Pro. Thank you for your business.', margin, 285);

  // Output logic
  if (viewMode) {
    // Generate a blob URL and open it in a new window
    const blobURL = pdf.output('bloburl');
    window.open(blobURL as any, '_blank');
  } else {
    // Standard download
    pdf.save(`${doc.type}_${doc.number}.pdf`);
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import Settings from './components/Settings';
import { AppState, DocumentType, TransactionType, Document } from './types';

const INITIAL_STATE: AppState = {
  business: {
    name: 'Acme Corp',
    email: 'contact@acmecorp.com',
    phone: '+1 (555) 012-3456',
    address: '123 Business Way, Tech City, TC 90210',
    taxId: 'TX-99887766',
    currency: 'USD'
  },
  documents: [],
  transactions: []
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('bizflow_state');
    return saved ? JSON.parse(saved) : INITIAL_STATE;
  });

  useEffect(() => {
    localStorage.setItem('bizflow_state', JSON.stringify(state));
  }, [state]);

  const updateBusiness = (business: AppState['business']) => {
    setState(prev => ({ ...prev, business }));
  };

  const addDocument = (doc: Document) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
  };

  const updateDocument = (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => d.id === doc.id ? doc : d)
    }));
  };

  const updateDocumentStatus = (id: string, status: any) => {
      setState(prev => ({
          ...prev,
          documents: prev.documents.map(d => d.id === id ? { ...d, status } : d)
      }));
  };

  const deleteDocument = (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
  };

  const addTransaction = (tx: any) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
  };

  const deleteTransaction = (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden">
        <Sidebar />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <Routes>
            <Route path="/" element={<Dashboard state={state} />} />
            <Route 
              path="/quotations" 
              element={<DocumentManager 
                type={DocumentType.QUOTATION} 
                state={state} 
                addDocument={addDocument}
                updateDocument={updateDocument}
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/invoices" 
              element={<DocumentManager 
                type={DocumentType.INVOICE} 
                state={state} 
                addDocument={addDocument}
                updateDocument={updateDocument}
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/sales" 
              element={<TransactionManager 
                type={TransactionType.SALE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/expenses" 
              element={<TransactionManager 
                type={TransactionType.EXPENSE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/settings" 
              element={<Settings business={state.business} updateBusiness={updateBusiness} />} 
            />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';
import { AppState, Document, DocumentType, LineItem } from '../types';
import { generatePDF } from '../utils/pdfGenerator';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  type: DocumentType;
  state: AppState;
  addDocument: (doc: Document) => void;
  updateDocument: (doc: Document) => void;
  deleteDocument: (id: string) => void;
  updateStatus: (id: string, status: any) => void;
}

const DocumentManager: React.FC<Props> = ({ type, state, addDocument, updateDocument, deleteDocument, updateStatus }) => {
  const [showModal, setShowModal] = useState(false);
  const [loadingSmart, setLoadingSmart] = useState(false);
  const [editingDocId, setEditingDocId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    notes: '',
    items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }] as LineItem[]
  });

  const filteredDocs = state.documents.filter(d => d.type === type);

  const resetForm = () => {
    setFormData({
      clientName: '',
      clientEmail: '',
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      notes: '',
      items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }]
    });
    setEditingDocId(null);
    setShowModal(false);
  };

  const handleEdit = (doc: Document) => {
    setFormData({
      clientName: doc.clientName,
      clientEmail: doc.clientEmail,
      date: doc.date,
      dueDate: doc.dueDate,
      notes: doc.notes || '',
      items: doc.items.map(item => ({ ...item }))
    });
    setEditingDocId(doc.id);
    setShowModal(true);
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (id: string) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (editingDocId) {
      const existingDoc = state.documents.find(d => d.id === editingDocId);
      if (existingDoc) {
        const updatedDoc: Document = {
          ...existingDoc,
          clientName: formData.clientName,
          clientEmail: formData.clientEmail,
          date: formData.date,
          dueDate: formData.dueDate,
          items: formData.items,
          notes: formData.notes
        };
        updateDocument(updatedDoc);
      }
    } else {
      const newDoc: Document = {
        id: Date.now().toString(),
        type,
        number: `${type === DocumentType.QUOTATION ? 'QT' : 'INV'}-${Math.floor(1000 + Math.random() * 9000)}`,
        clientName: formData.clientName,
        clientEmail: formData.clientEmail,
        date: formData.date,
        dueDate: formData.dueDate,
        items: formData.items,
        status: 'Draft',
        notes: formData.notes
      };
      addDocument(newDoc);
    }

    resetForm();
  };

  const handleSmartGenerate = async () => {
    setLoadingSmart(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Generate 3 professional service line items for a business in the ${state.business.name} industry.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            description: {
                                type: Type.STRING,
                                description: 'Clear and professional description of the service item.'
                            },
                            unitPrice: {
                                type: Type.NUMBER,
                                description: 'Typical market rate for this service.'
                            }
                        },
                        required: ['description', 'unitPrice'],
                        propertyOrdering: ['description', 'unitPrice']
                    }
                }
            }
        });

        const textOutput = response.text;
        const items = JSON.parse(textOutput || '[]');

        setFormData(prev => ({
            ...prev,
            items: items.map((it: any, idx: number) => ({
                id: `smart-${idx}-${Date.now()}`,
                description: it.description,
                quantity: 1,
                unitPrice: it.unitPrice
            }))
        }));
    } catch (err) {
        console.error("AI Error:", err);
    } finally {
        setLoadingSmart(false);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">{type === DocumentType.QUOTATION ? 'Quotations' : 'Invoices'}</h1>
          <p className="text-slate-500">Manage your business documents here.</p>
        </div>
        <button 
          onClick={() => { resetForm(); setShowModal(true); }}
          className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-semibold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all flex items-center gap-2"
        >
          <i className="fa-solid fa-plus"></i>
          Create {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Number</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Client</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Date</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Amount</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Status</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredDocs.length === 0 ? (
                <tr>
                    <td colSpan={6} className="px-6 py-12 text-center text-slate-400">
                        <i className="fa-solid fa-folder-open text-4xl mb-3 block"></i>
                        No records found.
                    </td>
                </tr>
            ) : filteredDocs.map(doc => {
              const total = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
              return (
                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-semibold text-slate-900">{doc.number}</td>
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-800">{doc.clientName}</div>
                    <div className="text-xs text-slate-500">{doc.clientEmail}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{doc.date}</td>
                  <td className="px-6 py-4 font-bold text-slate-900">{state.business.currency} {total.toLocaleString()}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      doc.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                      doc.status === 'Draft' ? 'bg-slate-100 text-slate-600' : 'bg-orange-100 text-orange-700'
                    }`}>
                      {doc.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-1">
                    <button 
                        onClick={() => handleEdit(doc)}
                        className="p-2 text-amber-600 hover:bg-amber-50 rounded-lg"
                        title="Edit Document"
                    >
                      <i className="fa-solid fa-pencil"></i>
                    </button>
                    <button 
                        onClick={() => generatePDF(doc, state.business, true)}
                        className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg"
                        title="View PDF"
                    >
                      <i className="fa-solid fa-eye"></i>
                    </button>
                    <button 
                        onClick={() => generatePDF(doc, state.business, false)}
                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                        title="Download PDF"
                    >
                      <i className="fa-solid fa-download"></i>
                    </button>
                    <button 
                        onClick={() => updateStatus(doc.id, 'Paid')}
                        className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg"
                        title="Mark as Paid"
                    >
                      <i className="fa-solid fa-check"></i>
                    </button>
                    <button 
                        onClick={() => deleteDocument(doc.id)}
                        className="p-2 text-red-600 hover:bg-red-50 rounded-lg"
                        title="Delete"
                    >
                      <i className="fa-solid fa-trash"></i>
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
              <h2 className="text-2xl font-bold text-slate-900">
                {editingDocId ? 'Edit' : 'Create New'} {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
              </h2>
              <button onClick={() => resetForm()} className="text-slate-400 hover:text-slate-600 p-2">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Name</label>
                  <input 
                    required
                    value={formData.clientName}
                    onChange={(e) => setFormData({...formData, clientName: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                    placeholder="Enter client's full name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Email</label>
                  <input 
                    required
                    type="email"
                    value={formData.clientEmail}
                    onChange={(e) => setFormData({...formData, clientEmail: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                    placeholder="client@example.com"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Document Date</label>
                  <input 
                    type="date"
                    value={formData.date}
                    onChange={(e) => setFormData({...formData, date: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Due Date</label>
                  <input 
                    type="date"
                    value={formData.dueDate}
                    onChange={(e) => setFormData({...formData, dueDate: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                  />
