                            {curr.code} ({curr.symbol}) - {curr.name}
                        </option>
                    ))}
                </select>
                <p className="mt-2 text-xs text-slate-500">This currency will be applied to all your future invoices, quotations, and financial reports.</p>
                </div>
            </div>
          </section>

          <div className="flex items-center justify-between pt-8 border-t border-slate-100">
            {isSaved ? (
                <span className="text-emerald-600 font-medium flex items-center gap-2 animate-bounceIn">
                    <i className="fa-solid fa-check-circle"></i> Business profile updated!
                </span>
            ) : <span className="text-slate-400 text-xs italic">* All fields are mandatory for compliant document generation</span>}
            <button 
              type="submit"
              className="px-12 py-3.5 bg-slate-900 text-white rounded-xl font-bold shadow-xl shadow-slate-200 hover:bg-black transition-all transform hover:-translate-y-1 active:translate-y-0"
            >
              Save Configuration
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useMemo } from 'react';
import { AppState, Document, DocumentType, LineItem } from '../types';
import { generatePDF } from '../utils/pdfGenerator';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  type: DocumentType;
  state: AppState;
  addDocument: (doc: Document) => void;
  updateDocument: (doc: Document) => void;
  deleteDocument: (id: string) => void;
  updateStatus: (id: string, status: any) => void;
}

const DocumentManager: React.FC<Props> = ({ type, state, addDocument, updateDocument, deleteDocument, updateStatus }) => {
  const [showModal, setShowModal] = useState(false);
  const [loadingSmart, setLoadingSmart] = useState(false);
  const [editingDocId, setEditingDocId] = useState<string | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    notes: '',
    items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }] as LineItem[]
  });

  const filteredDocs = state.documents.filter(d => d.type === type);

  // Calculate live total
  const currentTotal = useMemo(() => {
    return formData.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  }, [formData.items]);

  const resetForm = () => {
    setFormData({
      clientName: '',
      clientEmail: '',
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      notes: '',
      items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }]
    });
    setEditingDocId(null);
    setShowModal(false);
  };

  const handleEdit = (doc: Document) => {
    setFormData({
      clientName: doc.clientName,
      clientEmail: doc.clientEmail,
      date: doc.date,
      dueDate: doc.dueDate,
      notes: doc.notes || '',
      items: doc.items.map(item => ({ ...item }))
    });
    setEditingDocId(doc.id);
    setShowModal(true);
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleRemoveItem = (id: string) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (editingDocId) {
      const existingDoc = state.documents.find(d => d.id === editingDocId);
      if (existingDoc) {
        const updatedDoc: Document = {
          ...existingDoc,
          clientName: formData.clientName,
          clientEmail: formData.clientEmail,
          date: formData.date,
          dueDate: formData.dueDate,
          items: formData.items,
          notes: formData.notes
        };
        updateDocument(updatedDoc);
      }
    } else {
      const newDoc: Document = {
        id: Date.now().toString(),
        type,
        number: `${type === DocumentType.QUOTATION ? 'QT' : 'INV'}-${Math.floor(1000 + Math.random() * 9000)}`,
        clientName: formData.clientName,
        clientEmail: formData.clientEmail,
        date: formData.date,
        dueDate: formData.dueDate,
        items: formData.items,
        status: 'Draft',
        notes: formData.notes
      };
      addDocument(newDoc);
    }

    resetForm();
  };

  const handleSmartGenerate = async () => {
    setLoadingSmart(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Generate 3 professional service line items for a business in the ${state.business.name} industry.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            description: {
                                type: Type.STRING,
                                description: 'Clear and professional description of the service item.'
                            },
                            unitPrice: {
                                type: Type.NUMBER,
                                description: 'Typical market rate for this service.'
                            }
                        },
                        required: ['description', 'unitPrice'],
                        propertyOrdering: ['description', 'unitPrice']
                    }
                }
            }
        });

        const textOutput = response.text;
        const items = JSON.parse(textOutput || '[]');

        setFormData(prev => ({
            ...prev,
            items: items.map((it: any, idx: number) => ({
                id: `smart-${idx}-${Date.now()}`,
                description: it.description,
                quantity: 1,
                unitPrice: it.unitPrice
            }))
        }));
    } catch (err) {
        console.error("AI Error:", err);
    } finally {
        setLoadingSmart(false);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">{type === DocumentType.QUOTATION ? 'Quotations' : 'Invoices'}</h1>
          <p className="text-slate-500">Manage your business documents here.</p>
        </div>
        <button 
          onClick={() => { resetForm(); setShowModal(true); }}
          className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-semibold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all flex items-center gap-2"
        >
          <i className="fa-solid fa-plus"></i>
          Create {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Number</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Client</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Date</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Amount</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Status</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredDocs.length === 0 ? (
                <tr>
                    <td colSpan={6} className="px-6 py-12 text-center text-slate-400">
                        <i className="fa-solid fa-folder-open text-4xl mb-3 block"></i>
                        No records found.
                    </td>
                </tr>
            ) : filteredDocs.map(doc => {
              const total = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
              return (
                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-semibold text-slate-900">{doc.number}</td>
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-800">{doc.clientName}</div>
                    <div className="text-xs text-slate-500">{doc.clientEmail}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{doc.date}</td>
                  <td className="px-6 py-4 font-bold text-slate-900">{state.business.currency} {total.toLocaleString()}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      doc.status === 'Paid' ? 'bg-emerald-100 text-emerald-700' : 
                      doc.status === 'Draft' ? 'bg-slate-100 text-slate-600' : 'bg-orange-100 text-orange-700'
                    }`}>
                      {doc.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-1">
                    <button 
                        onClick={() => handleEdit(doc)}
                        className="p-2 text-amber-600 hover:bg-amber-50 rounded-lg"
                        title="Edit Document"
                    >
                      <i className="fa-solid fa-pencil"></i>
                    </button>
                    <button 
                        onClick={() => generatePDF(doc, state.business, true)}
                        className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg"
                        title="View PDF"
                    >
                      <i className="fa-solid fa-eye"></i>
                    </button>
                    <button 
                        onClick={() => generatePDF(doc, state.business, false)}
                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                        title="Download PDF"
                    >
                      <i className="fa-solid fa-download"></i>
                    </button>
                    <button 
                        onClick={() => updateStatus(doc.id, 'Paid')}
                        className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg"
                        title="Mark as Paid"
                    >
                      <i className="fa-solid fa-check"></i>
                    </button>
                    <button 
                        onClick={() => deleteDocument(doc.id)}
                        className="p-2 text-red-600 hover:bg-red-50 rounded-lg"
                        title="Delete"
                    >
                      <i className="fa-solid fa-trash"></i>
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
              <h2 className="text-2xl font-bold text-slate-900">
                {editingDocId ? 'Edit' : 'Create New'} {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
              </h2>
              <button onClick={() => resetForm()} className="text-slate-400 hover:text-slate-600 p-2">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Name</label>
                  <input 
                    required
                    value={formData.clientName}
                    onChange={(e) => setFormData({...formData, clientName: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                    placeholder="Enter client's full name"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Email</label>
                  <input 
                    required
                    type="email"
                    value={formData.clientEmail}
                    onChange={(e) => setFormData({...formData, clientEmail: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                    placeholder="client@example.com"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Document Date</label>
                  <input 
                    type="date"
                    value={formData.date}
                    onChange={(e) => setFormData({...formData, date: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Due Date</label>
                  <input 
                    type="date"
                    value={formData.dueDate}
                    onChange={(e) => setFormData({...formData, dueDate: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" 
                  />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Line Items</h3>
                    <button 
                        type="button"
                        disabled={loadingSmart}
                        onClick={handleSmartGenerate}
                        className="text-blue-600 text-sm font-semibold hover:underline flex items-center gap-1"
                    >
                        <i className={`fa-solid ${loadingSmart ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                        {loadingSmart ? 'Thinking...' : 'AI Suggest Items'}
                    </button>
                </div>

                {/* Column Headers */}
                <div className="hidden md:flex gap-4 px-4 text-xs font-bold text-slate-500 uppercase tracking-wider">
                  <div className="flex-1">Description</div>
                  <div className="w-24">Quantity</div>
                  <div className="w-32">Unit Price ({state.business.currency})</div>
                  <div className="w-32">Amount</div>
                  <div className="w-10"></div>
                </div>

                <div className="space-y-3">
                  {formData.items.map((item, index) => (
                    <div key={item.id} className="flex flex-col md:flex-row gap-4 items-start bg-slate-50 p-4 rounded-xl border border-slate-100">
                      <div className="flex-1 w-full">
                        <input 
                          placeholder="Description"
                          value={item.description}
                          onChange={(e) => handleItemChange(item.id, 'description', e.target.value)}
                          className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" 
                        />
                      </div>
                      <div className="w-full md:w-24">
                        <label className="block md:hidden text-[10px] font-bold text-slate-400 uppercase mb-1">Qty</label>
                        <input 
                          type="number"
                          placeholder="Qty"
                          min="1"
                          value={item.quantity}
                          onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value))}
                          className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" 
                        />
                      </div>
                      <div className="w-full md:w-32">
                        <label className="block md:hidden text-[10px] font-bold text-slate-400 uppercase mb-1">Price</label>
                        <input 
                          type="number"
                          placeholder="Price"
                          value={item.unitPrice}
                          onChange={(e) => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value))}
                          className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" 
                        />
                      </div>
                      <div className="w-full md:w-32 flex items-center h-full md:pt-2">
                        <label className="block md:hidden text-[10px] font-bold text-slate-400 uppercase mb-1 mr-2">Total:</label>
                        <span className="font-bold text-slate-700">
                          {state.business.currency} {(item.quantity * item.unitPrice).toLocaleString(undefined, { minimumFractionDigits: 2 })}
                        </span>
                      </div>
                      <button 
                        type="button"
                        onClick={() => handleRemoveItem(item.id)}
                        className="p-2 text-slate-400 hover:text-red-500 transition-colors md:pt-2"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                  ))}
                </div>

                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 pt-2">
                  <button 
                    type="button"
                    onClick={handleAddItem}
                    className="flex-1 w-full border-2 border-dashed border-slate-200 rounded-xl py-3 text-slate-500 font-medium hover:border-blue-400 hover:text-blue-500 transition-all"
                  >
                    <i className="fa-solid fa-plus mr-2"></i>Add Another Item
                  </button>

                  <div className="w-full md:w-64 bg-slate-900 text-white rounded-xl p-4 shadow-lg">
                    <div className="flex justify-between items-center mb-1">
                      <span className="text-xs text-slate-400 font-bold uppercase tracking-widest">Document Total</span>
                    </div>
                    <div className="text-2xl font-black">
                      {state.business.currency} {currentTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                    </div>
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Notes & Terms</label>
                <textarea 
                  value={formData.notes}
                  onChange={(e) => setFormData({...formData, notes: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all min-h-[100px] text-slate-900" 
                  placeholder="Additional information for the client..."
                />
              </div>

              <div className="flex justify-end gap-4 border-t border-slate-100 pt-8">
                <button 
                  type="button"
                  onClick={() => resetForm()}
                  className="px-6 py-3 border border-slate-200 rounded-xl font-semibold text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all"
                >
                  {editingDocId ? 'Update Document' : 'Save & Generate'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DocumentManager;

import React, { useState, useRef } from 'react';
import { BusinessDetails } from '../types';

interface Props {
  business: BusinessDetails;
  updateBusiness: (details: BusinessDetails) => void;
}

const CURRENCIES = [
    { code: 'MVR', symbol: 'Rf', name: 'Maldivian Rufiyaa' },
    { code: 'USD', symbol: '$', name: 'US Dollar' }
];

const Settings: React.FC<Props> = ({ business, updateBusiness }) => {
  const [details, setDetails] = useState<BusinessDetails>(business);
  const [isSaved, setIsSaved] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateBusiness(details);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleLogoClick = () => {
    fileInputRef.current?.click();
  };

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setDetails(prev => ({ ...prev, logoUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLogo = (e: React.MouseEvent) => {
    e.stopPropagation();
    setDetails(prev => ({ ...prev, logoUrl: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
      <header>
        <h1 className="text-3xl font-bold text-slate-900">Settings</h1>
        <p className="text-slate-500">Configure your company identity and regional preferences.</p>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-8 border-b border-slate-100 bg-slate-50/50">
            <div className="flex items-center gap-6">
                <div 
                  onClick={handleLogoClick}
                  className="group relative w-24 h-24 rounded-2xl bg-slate-200 flex items-center justify-center border-4 border-white shadow-sm overflow-hidden cursor-pointer hover:bg-slate-300 transition-all"
                >
                    {details.logoUrl ? (
                      <img src={details.logoUrl} className="w-full h-full object-cover" alt="Business Logo" />
                    ) : (
                      <i className="fa-solid fa-building text-4xl text-slate-400"></i>
                    )}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <i className="fa-solid fa-camera text-white text-xl"></i>
                    </div>
                </div>

                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*"
                  onChange={handleLogoChange}
                />

                <div>
                    <h2 className="text-xl font-bold text-slate-800">{details.name || 'Your Company Name'}</h2>
                    <p className="text-slate-500 text-sm">Update your logo and business information</p>
                    <div className="flex gap-4 mt-2">
                      <button 
                        type="button" 
                        onClick={handleLogoClick}
                        className="text-blue-600 text-sm font-semibold hover:underline flex items-center gap-1"
                      >
                        <i className="fa-solid fa-upload"></i>
                        Change Logo
                      </button>
                      {details.logoUrl && (
                        <button 
                          type="button" 
                          onClick={removeLogo}
                          className="text-red-500 text-sm font-semibold hover:underline flex items-center gap-1"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                          Remove
                        </button>
                      )}
                    </div>
                </div>
            </div>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-10">
          <section className="space-y-6">
            <h3 className="text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Business Identity</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Company Name</label>
                <input 
                    required
                    value={details.name}
                    onChange={(e) => setDetails({...details, name: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Business Email</label>
                <input 
                    required
                    type="email"
                    value={details.email}
                    onChange={(e) => setDetails({...details, email: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Phone Number</label>
                <input 
                    required
                    value={details.phone}
                    onChange={(e) => setDetails({...details, phone: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                />
                </div>
                <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Physical Address</label>
                <input 
