                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                  ))}
                </div>

                <div className="flex flex-col md:flex-row justify-between items-start gap-4 pt-4">
                  <button 
                    type="button"
                    onClick={handleAddItem}
                    className="flex-1 w-full border-2 border-dashed border-slate-200 rounded-xl py-3 text-slate-500 font-medium hover:border-blue-400 hover:text-blue-500 transition-all"
                  >
                    <i className="fa-solid fa-plus mr-2"></i>Add Another Item
                  </button>

                  <div className="w-full md:w-72 bg-slate-900 text-white rounded-2xl p-6 shadow-xl space-y-3">
                    <div className="flex justify-between items-center text-sm text-slate-400">
                      <span>Subtotal</span>
                      <span>{state.business.currency} {currentSubtotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                    </div>
                    <div className="flex justify-between items-center text-sm text-slate-400">
                      <span>Tax ({state.business.taxPercentage}%)</span>
                      <span>{state.business.currency} {currentTaxAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                    </div>
                    <div className="pt-2 border-t border-slate-800 flex justify-between items-center">
                      <span className="text-xs font-bold uppercase tracking-widest">Total Amount</span>
                      <span className="text-2xl font-black">
                        {state.business.currency} {currentTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                      </span>
                    </div>
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Notes & Terms</label>
                <textarea 
                  value={formData.notes}
                  onChange={(e) => setFormData({...formData, notes: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all min-h-[100px] text-slate-900" 
                  placeholder="Additional information for the client..."
                />
              </div>

              <div className="flex justify-end gap-4 border-t border-slate-100 pt-8">
                <button 
                  type="button"
                  onClick={() => resetForm()}
                  className="px-6 py-3 border border-slate-200 rounded-xl font-semibold text-slate-600 hover:bg-slate-50 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all"
                >
                  {editingDocId ? 'Update Document' : 'Save & Generate'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

