import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Document, BusinessDetails } from '../types';

export const generatePDF = (doc: Document, business: BusinessDetails, viewMode: boolean = false) => {
  const pdf = new jsPDF();
  const margin = 20;
  const pageWidth = pdf.internal.pageSize.width;

  // Primary Accent Color (Matches Tailwind blue-600)
  const accentColor: [number, number, number] = [37, 99, 235];
  const secondaryColor: [number, number, number] = [15, 23, 42]; // Slate-900
  const lightGray: [number, number, number] = [100, 116, 139]; // Slate-500

  // 1. Top Decorative Bar
  pdf.setFillColor(...accentColor);
  pdf.rect(0, 0, pageWidth, 2, 'F');

  // Dynamic Y positioning based on logo presence
  let currentY = margin;

  // 2. Logo (Top Left)
  if (business.logoUrl) {
    try {
      // Placing logo at the top left. Max width 45mm, max height 20mm.
      pdf.addImage(business.logoUrl, 'PNG', margin, currentY, 40, 20, undefined, 'FAST');
      currentY += 25; // Shift following content down
    } catch (e) {
      console.error("Failed to add logo to PDF", e);
    }
  }

  // 3. Header: Business Info (Left)
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(22);
  pdf.setTextColor(...secondaryColor);
  pdf.text(business.name.toUpperCase(), margin, currentY + 8);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text([
    business.address,
    `${business.email}  |  ${business.phone}`,
    `TIN Number: ${business.tinNumber}`
  ], margin, currentY + 16, { lineHeightFactor: 1.5 });

  // 4. Document Metadata (Right)
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(14);
  pdf.setTextColor(...accentColor);
  pdf.text(doc.type.toUpperCase(), pageWidth - margin, currentY + 8, { align: 'right' });

  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text(`NO: ${doc.number}`, pageWidth - margin, currentY + 16, { align: 'right' });

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(`Issue Date: ${doc.date}`, pageWidth - margin, currentY + 22, { align: 'right' });
  pdf.text(`Due Date: ${doc.dueDate}`, pageWidth - margin, currentY + 27, { align: 'right' });

  // 5. Horizontal Line
  pdf.setDrawColor(241, 245, 249); // Slate-100
  pdf.line(margin, currentY + 36, pageWidth - margin, currentY + 36);

  // 6. Bill To Section
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('BILL TO', margin, currentY + 46);

  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(11);
  pdf.text(doc.clientName, margin, currentY + 53);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(doc.clientEmail, margin, currentY + 58);

  // 7. Main Table
  const tableHeaders = [['DESCRIPTION', 'QTY', 'UNIT PRICE', 'TOTAL']];
  const tableData = doc.items.map(item => [
    item.description,
    item.quantity.toString(),
    `${business.currency} ${item.unitPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}`,
    `${business.currency} ${(item.quantity * item.unitPrice).toLocaleString(undefined, { minimumFractionDigits: 2 })}`
  ]);

  const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  const taxAmount = (subtotal * business.taxPercentage) / 100;
  const total = subtotal + taxAmount;

  autoTable(pdf, {
    startY: currentY + 68,
    head: tableHeaders,
    body: tableData,
    theme: 'plain',
    headStyles: { 
      fillColor: [248, 250, 252], // Slate-50
      textColor: secondaryColor,
      fontStyle: 'bold',
      fontSize: 9,
      cellPadding: 4
    },
    bodyStyles: { 
      fontSize: 9,
      textColor: secondaryColor,
      cellPadding: 4
    },
    columnStyles: {
      1: { halign: 'center' },
      2: { halign: 'right' },
      3: { halign: 'right', fontStyle: 'bold' }
    },
    margin: { left: margin, right: margin },
    didDrawCell: (data) => {
        if (data.section === 'body') {
            pdf.setDrawColor(241, 245, 249);
            pdf.line(data.cell.x, data.cell.y + data.cell.height, data.cell.x + data.cell.width, data.cell.y + data.cell.height);
        }
    }
  });

  // 8. Summary Block
  const finalY = (pdf as any).lastAutoTable?.finalY || 150;

  // Subtotal line
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text('Subtotal:', pageWidth - margin - 50, finalY + 12);
  pdf.text(`${business.currency} ${subtotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, pageWidth - margin, finalY + 12, { align: 'right' });

  // Tax line
  pdf.text(`Tax (${business.taxPercentage}%):`, pageWidth - margin - 50, finalY + 18);
  pdf.text(`${business.currency} ${taxAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, pageWidth - margin, finalY + 18, { align: 'right' });

  // Total amount line
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('TOTAL AMOUNT DUE:', pageWidth - margin - 50, finalY + 28);

  pdf.setFontSize(16);
  pdf.setTextColor(...accentColor);
  pdf.text(`${business.currency} ${total.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, pageWidth - margin, finalY + 28, { align: 'right' });

  // 9. Notes & Payment Status
  if (doc.notes) {
    pdf.setFont('helvetica', 'bold');
    pdf.setFontSize(9);
    pdf.setTextColor(...secondaryColor);
    pdf.text('NOTES & TERMS', margin, finalY + 15);

    pdf.setFont('helvetica', 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(...lightGray);
    const splitNotes = pdf.splitTextToSize(doc.notes, 100);
    pdf.text(splitNotes, margin, finalY + 20);
  }

  // 10. Paid Watermark
  if (doc.status === 'Paid') {
    pdf.setTextColor(16, 185, 129, 0.2); // Emerald-500
    pdf.setFontSize(60);
    pdf.setFont('helvetica', 'bold');
    pdf.saveGraphicsState();
    pdf.rotate(-25, pageWidth / 2, finalY + 50);
    pdf.text('PAID', pageWidth / 2 - 40, finalY + 60);
    pdf.restoreGraphicsState();
  }

  // 11. Footer
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(8);
  pdf.setTextColor(...lightGray);
  pdf.text(`Powered by BizFlow Pro  |  Business TIN: ${business.tinNumber}`, pageWidth / 2, 285, { align: 'center' });

  // Output logic
  if (viewMode) {
    const blobURL = pdf.output('bloburl');
    window.open(blobURL as any, '_blank');
  } else {
    pdf.save(`${doc.type}_${doc.number}.pdf`);
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import Settings from './components/Settings';
import { AppState, DocumentType, TransactionType, Document } from './types';

const INITIAL_STATE: AppState = {
  business: {
    name: 'SANDPIX MALDIVES',
    email: 'info@sandpixmaldives.com',
    phone: '+960 797 3617',
    address: 'Blue House, HDh. Nellaidhoo, Maldives',
    tinNumber: '1106645GST501',
    currency: 'MVR',
    taxPercentage: 8
  },
  documents: [],
  transactions: []
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('bizflow_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Migration for renaming taxId to tinNumber if it exists in old storage
      if (parsed.business && parsed.business.taxId !== undefined) {
        parsed.business.tinNumber = parsed.business.taxId;
        delete parsed.business.taxId;
      }
      // Ensure taxPercentage exists
      if (parsed.business && parsed.business.taxPercentage === undefined) {
        parsed.business.taxPercentage = INITIAL_STATE.business.taxPercentage;
      }
      return parsed;
    }
    return INITIAL_STATE;
  });

  useEffect(() => {
    localStorage.setItem('bizflow_state', JSON.stringify(state));
  }, [state]);

  const updateBusiness = (business: AppState['business']) => {
    setState(prev => ({ ...prev, business }));
  };

  const addDocument = (doc: Document) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
  };

  const updateDocument = (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => d.id === doc.id ? doc : d)
    }));
  };

  const updateDocumentStatus = (id: string, status: any) => {
      setState(prev => ({
          ...prev,
          documents: prev.documents.map(d => d.id === id ? { ...d, status } : d)
      }));
  };

  const deleteDocument = (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
  };

  const addTransaction = (tx: any) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
  };

  const deleteTransaction = (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden">
        <Sidebar />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <Routes>
            <Route path="/" element={<Dashboard state={state} />} />
            <Route 
              path="/quotations" 
              element={<DocumentManager 
                type={DocumentType.QUOTATION} 
                state={state} 
                addDocument={addDocument}
                updateDocument={updateDocument}
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/invoices" 
              element={<DocumentManager 
                type={DocumentType.INVOICE} 
                state={state} 
                addDocument={addDocument}
                updateDocument={updateDocument}
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/sales" 
              element={<TransactionManager 
                type={TransactionType.SALE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/expenses" 
              element={<TransactionManager 
                type={TransactionType.EXPENSE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/settings" 
              element={<Settings business={state.business} updateBusiness={updateBusiness} />} 
            />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

