import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Document, BusinessDetails } from '../types';

export const generatePDF = (doc: Document, business: BusinessDetails, viewMode: boolean = false) => {
  const pdf = new jsPDF();
  const margin = 20;
  const pageWidth = pdf.internal.pageSize.width;

  // Primary Accent Color (Matches Tailwind blue-600)
  const accentColor: [number, number, number] = [37, 99, 235];
  const secondaryColor: [number, number, number] = [15, 23, 42]; // Slate-900
  const lightGray: [number, number, number] = [100, 116, 139]; // Slate-500

  // 1. Top Decorative Bar
  pdf.setFillColor(...accentColor);
  pdf.rect(0, 0, pageWidth, 2, 'F');

  let currentY = margin;

  // 2. Logo (Top Left)
  if (business.logoUrl) {
    try {
      pdf.addImage(business.logoUrl, 'PNG', margin, currentY, 35, 15, undefined, 'FAST');
      currentY += 20; 
    } catch (e) {
      console.error("Failed to add logo to PDF", e);
    }
  }

  // 3. Header Section (Top Right Metadata)
  const rightAlignX = pageWidth - margin;
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(24);
  pdf.setTextColor(...accentColor);
  pdf.text(doc.type.toUpperCase(), rightAlignX, currentY + 5, { align: 'right' });

  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text(`DOCUMENT NO: ${doc.number}`, rightAlignX, currentY + 12, { align: 'right' });

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(`Issue Date: ${doc.date}`, rightAlignX, currentY + 18, { align: 'right' });
  pdf.text(`Due Date: ${doc.dueDate}`, rightAlignX, currentY + 23, { align: 'right' });

  // 4. Header Section (Top Left Business Info)
  // We use the same currentY baseline as the Right Metadata
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(18);
  pdf.setTextColor(...secondaryColor);
  pdf.text(business.name.toUpperCase(), margin, currentY + 5);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);

  // Splitting address to avoid extremely long lines
  const addressLines = pdf.splitTextToSize(business.address, 80);
  pdf.text(addressLines, margin, currentY + 12);

  // Calculate next position after address lines
  const addressHeight = addressLines.length * 5;
  const contactY = currentY + 12 + addressHeight;

  pdf.text(`${business.email}`, margin, contactY);
  pdf.text(`${business.phone}`, margin, contactY + 5);
  pdf.setFont('helvetica', 'bold');
  pdf.setTextColor(...secondaryColor);
  pdf.text(`TIN: ${business.tinNumber}`, margin, contactY + 10);

  // 5. Section Divider
  currentY = Math.max(currentY + 30, contactY + 15);
  pdf.setDrawColor(241, 245, 249); 
  pdf.line(margin, currentY, pageWidth - margin, currentY);

  // 6. Bill To Section
  currentY += 10;
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('BILL TO', margin, currentY);

  pdf.setFontSize(12);
  pdf.text(doc.clientName, margin, currentY + 7);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(doc.clientEmail, margin, currentY + 13);

  // 7. Main Table
  const tableHeaders = [['DESCRIPTION', 'QTY', 'UNIT PRICE', 'TOTAL']];
  const tableData = doc.items.map(item => [
    item.description,
    item.quantity.toString(),
    `${business.currency} ${item.unitPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}`,
    `${business.currency} ${(item.quantity * item.unitPrice).toLocaleString(undefined, { minimumFractionDigits: 2 })}`
  ]);

  const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  const taxAmount = (subtotal * business.taxPercentage) / 100;
  const total = subtotal + taxAmount;

  autoTable(pdf, {
    startY: currentY + 22,
    head: tableHeaders,
    body: tableData,
    theme: 'plain',
    headStyles: { 
      fillColor: [248, 250, 252], 
      textColor: secondaryColor,
      fontStyle: 'bold',
      fontSize: 9,
      cellPadding: 4
    },
    bodyStyles: { 
      fontSize: 9,
      textColor: secondaryColor,
      cellPadding: 4
    },
    columnStyles: {
      0: { cellWidth: 'auto' },
      1: { halign: 'center', cellWidth: 20 },
      2: { halign: 'right', cellWidth: 40 },
      3: { halign: 'right', fontStyle: 'bold', cellWidth: 40 }
    },
    margin: { left: margin, right: margin },
    didDrawCell: (data) => {
        if (data.section === 'body') {
            pdf.setDrawColor(241, 245, 249);
            pdf.line(data.cell.x, data.cell.y + data.cell.height, data.cell.x + data.cell.width, data.cell.y + data.cell.height);
        }
    }
  });

  // 8. Summary Block & Notes
  let finalY = (pdf as any).lastAutoTable?.finalY || 150;

  // Add some breathing room after table
  finalY += 10;

  // Notes on the left (taking 50% width)
  if (doc.notes) {
    pdf.setFont('helvetica', 'bold');
    pdf.setFontSize(9);
    pdf.setTextColor(...secondaryColor);
    pdf.text('NOTES & TERMS', margin, finalY);

    pdf.setFont('helvetica', 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(...lightGray);
    const splitNotes = pdf.splitTextToSize(doc.notes, 100);
    pdf.text(splitNotes, margin, finalY + 5);
  }

  // Summary Totals on the right
  const summaryX = pageWidth - margin;
  const labelX = pageWidth - margin - 50;

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);

  pdf.text('Subtotal:', labelX, finalY);
  pdf.text(`${business.currency} ${subtotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, finalY, { align: 'right' });

  pdf.text(`Tax (${business.taxPercentage}%):`, labelX, finalY + 7);
  pdf.text(`${business.currency} ${taxAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, finalY + 7, { align: 'right' });

  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('TOTAL AMOUNT:', labelX, finalY + 16);

  pdf.setFontSize(16);
  pdf.setTextColor(...accentColor);
  pdf.text(`${business.currency} ${total.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, finalY + 16, { align: 'right' });

  // 10. Paid Watermark
  if (doc.status === 'Paid') {
    pdf.setTextColor(16, 185, 129, 0.15); // Emerald-500 light
    pdf.setFontSize(60);
    pdf.setFont('helvetica', 'bold');
    pdf.saveGraphicsState();
    // Centered relative to the page
    pdf.rotate(-25, pageWidth / 2, 200);
    pdf.text('PAID', pageWidth / 2 - 40, 210);
    pdf.restoreGraphicsState();
  }

  // 11. Footer
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(8);
  pdf.setTextColor(...lightGray);
  pdf.text(`This is a computer generated document. All rights reserved.`, pageWidth / 2, 285, { align: 'center' });
  pdf.text(`${business.name} | TIN: ${business.tinNumber}`, pageWidth / 2, 290, { align: 'center' });

  // Output logic
  if (viewMode) {
    const blobURL = pdf.output('bloburl');
    window.open(blobURL as any, '_blank');
  } else {
    pdf.save(`${doc.type}_${doc.number}.pdf`);
  }
};

