import React, { useState, useMemo } from 'react';
import { AppState, Transaction, TransactionType } from '../types';

interface Props {
  type: TransactionType;
  state: AppState;
  addTransaction: (tx: Transaction) => void;
  deleteTransaction: (id: string) => void;
}

const TransactionManager: React.FC<Props> = ({ type, state, addTransaction, deleteTransaction }) => {
  const [showModal, setShowModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    category: '',
    amount: 0,
    description: '',
    reference: ''
  });

  const filteredTransactions = useMemo(() => {
    const txs = state.transactions.filter(t => t.type === type);
    if (!searchTerm.trim()) return txs;

    const term = searchTerm.toLowerCase();
    return txs.filter(t => 
      t.description.toLowerCase().includes(term) ||
      t.category.toLowerCase().includes(term) ||
      (t.reference && t.reference.toLowerCase().includes(term))
    );
  }, [state.transactions, type, searchTerm]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newTx: Transaction = {
      id: Date.now().toString(),
      type,
      ...formData
    };
    addTransaction(newTx);
    setShowModal(false);
    setFormData({
      date: new Date().toISOString().split('T')[0],
      category: '',
      amount: 0,
      description: '',
      reference: ''
    });
  };

  const categories = type === TransactionType.SALE 
    ? ['Product Sales', 'Service Fees', 'Subscription', 'Consulting', 'Other']
    : ['Rent', 'Utilities', 'Salaries', 'Software', 'Marketing', 'Supplies', 'Other'];

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">{type === TransactionType.SALE ? 'Sales Ledger' : 'Expense Tracker'}</h1>
          <p className="text-slate-500">Keep track of your {type.toLowerCase()} transactions.</p>
        </div>
        <div className="flex w-full md:w-auto items-center gap-3">
            <div className="relative flex-1 md:w-64">
                <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
                <input 
                    type="text"
                    placeholder="Search records..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all shadow-sm"
                />
            </div>
            <button 
                onClick={() => setShowModal(true)}
                className={`px-5 py-2.5 rounded-xl font-semibold shadow-lg transition-all flex items-center gap-2 text-white whitespace-nowrap ${
                    type === TransactionType.SALE ? 'bg-emerald-600 shadow-emerald-100 hover:bg-emerald-700' : 'bg-red-600 shadow-red-100 hover:bg-red-700'
                }`}
            >
                <i className="fa-solid fa-plus"></i>
                Add {type === TransactionType.SALE ? 'Sale' : 'Expense'}
            </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Date</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Category</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Description</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Amount</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase text-right">Action</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredTransactions.length === 0 ? (
                <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                         {searchTerm ? 'No matches found.' : 'No transactions recorded yet.'}
                    </td>
                </tr>
            ) : filteredTransactions.map(tx => (
              <tr key={tx.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 text-slate-600">{tx.date}</td>
                <td className="px-6 py-4">
                  <span className="bg-slate-100 text-slate-700 px-3 py-1 rounded-full text-xs font-semibold">
                    {tx.category}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <div className="text-slate-800 font-medium">{tx.description}</div>
                  {tx.reference && <div className="text-xs text-slate-400">Ref: {tx.reference}</div>}
                </td>
                <td className={`px-6 py-4 font-bold ${type === TransactionType.SALE ? 'text-emerald-600' : 'text-red-600'}`}>
                   {type === TransactionType.SALE ? '+' : '-'}{state.business.currency} {tx.amount.toLocaleString()}
                </td>
                <td className="px-6 py-4 text-right">
                  <button 
                    onClick={() => deleteTransaction(tx.id)}
                    className="text-red-400 hover:text-red-600"
