                        </div>
                    </div>
                </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default DocumentManager;

export enum DocumentType {
  QUOTATION = 'QUOTATION',
  INVOICE = 'INVOICE'
}

export enum TransactionType {
  SALE = 'SALE',
  EXPENSE = 'EXPENSE'
}

export interface BusinessDetails {
  name: string;
  email: string;
  phone: string;
  address: string;
  tinNumber: string;
  currency: string;
  taxPercentage: number;
  invoicePrefix: string;
  quotationPrefix: string;
  logoUrl?: string;
  defaultTerms?: string;
  paymentDetails?: string;
}

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface CatalogItem {
  id: string;
  description: string;
  unitPrice: number;
}

export interface Document {
  id: string;
  type: DocumentType;
  number: string;
  date: string;
  dueDate: string;
  clientName: string;
  clientEmail: string;
  items: LineItem[];
  status: 'Draft' | 'Sent' | 'Paid' | 'Expired';
  notes?: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  date: string;
  category: string;
  amount: number;
  description: string;
  reference?: string;
}

export interface AppState {
  business: BusinessDetails;
  documents: Document[];
  transactions: Transaction[];
  catalog: CatalogItem[];
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import CatalogManager from './components/CatalogManager';
import Settings from './components/Settings';
import { AppState, DocumentType, TransactionType, Document, Transaction, CatalogItem } from './types';

const INITIAL_STATE: AppState = {
  business: {
    name: 'SANDPIX MALDIVES',
    email: 'info@sandpixmaldives.com',
    phone: '+960 797 3617',
    address: 'Blue House, HDh. Nellaidhoo, Maldives',
    tinNumber: '1106645GST501',
    currency: 'MVR',
    taxPercentage: 8,
    invoicePrefix: 'INV',
    quotationPrefix: 'QT',
    defaultTerms: '1. Please pay within 7 days.\n2. Goods once sold are not returnable.',
    paymentDetails: 'Bank: Bank of Maldives (BML)\nAccount Name: SANDPIX MALDIVES\nAccount Number: 7730000000001\nBranch: Main Branch'
  },
  documents: [],
  transactions: [],
  catalog: []
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('bizflow_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Migration logic for catalog
      if (!parsed.catalog) parsed.catalog = [];
      // Migration for document prefixes
      if (!parsed.business.invoicePrefix) parsed.business.invoicePrefix = 'INV';
      if (!parsed.business.quotationPrefix) parsed.business.quotationPrefix = 'QT';
      return parsed;
    }
    return INITIAL_STATE;
  });

  useEffect(() => {
    localStorage.setItem('bizflow_state', JSON.stringify(state));
  }, [state]);

  const updateBusiness = (business: AppState['business']) => {
    setState(prev => ({ ...prev, business }));
  };

  const addDocument = (doc: Document) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
  };

  const updateDocument = (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => d.id === doc.id ? doc : d)
    }));
  };

  const updateDocumentStatus = (id: string, status: 'Draft' | 'Sent' | 'Paid' | 'Expired') => {
      setState(prev => {
          const doc = prev.documents.find(d => d.id === id);
          if (!doc) return prev;

          let newTransactions = prev.transactions;
          if (doc.type === DocumentType.INVOICE && status === 'Paid' && doc.status !== 'Paid') {
              const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
              const taxAmount = (subtotal * prev.business.taxPercentage) / 100;
              const total = subtotal + taxAmount;

              const newSale: Transaction = {
                  id: `sale-inv-${doc.id}-${Date.now()}`,
                  type: TransactionType.SALE,
                  date: new Date().toISOString().split('T')[0],
                  category: 'Product Sales',
                  amount: total,
                  description: `Payment for Invoice ${doc.number}`,
                  reference: doc.number
              };
              newTransactions = [newSale, ...prev.transactions];
          }

          return {
              ...prev,
              documents: prev.documents.map(d => d.id === id ? { ...d, status } : d),
              transactions: newTransactions
          };
      });
  };

  const deleteDocument = (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
  };

  const addTransaction = (tx: Transaction) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
  };

  const deleteTransaction = (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
  };

  const addCatalogItem = (item: CatalogItem) => {
    setState(prev => ({ ...prev, catalog: [item, ...prev.catalog] }));
  };

  const updateCatalogItem = (item: CatalogItem) => {
    setState(prev => ({
      ...prev,
      catalog: prev.catalog.map(i => i.id === item.id ? item : i)
    }));
  };

  const deleteCatalogItem = (id: string) => {
    setState(prev => ({ ...prev, catalog: prev.catalog.filter(i => i.id !== id) }));
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden">
        <Sidebar />
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <Routes>
            <Route path="/" element={<Dashboard state={state} />} />
            <Route 
              path="/quotations" 
              element={<DocumentManager 
                type={DocumentType.QUOTATION} 
                state={state} 
                addDocument={addDocument}
                updateDocument={updateDocument}
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/invoices" 
              element={<DocumentManager 
                type={DocumentType.INVOICE} 
                state={state} 
                addDocument={addDocument}
                updateDocument={updateDocument}
                deleteDocument={deleteDocument}
                updateStatus={updateDocumentStatus}
              />} 
            />
            <Route 
              path="/catalog" 
              element={<CatalogManager 
                state={state} 
                addItem={addCatalogItem}
                updateItem={updateCatalogItem}
                deleteItem={deleteCatalogItem}
              />} 
            />
            <Route 
              path="/sales" 
              element={<TransactionManager 
                type={TransactionType.SALE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/expenses" 
              element={<TransactionManager 
                type={TransactionType.EXPENSE} 
                state={state} 
                addTransaction={addTransaction} 
                deleteTransaction={deleteTransaction}
              />} 
            />
            <Route 
              path="/settings" 
              element={<Settings business={state.business} updateBusiness={updateBusiness} />} 
            />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { BusinessDetails } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  business: BusinessDetails;
  updateBusiness: (details: BusinessDetails) => void;
}

const CURRENCIES = [
    { code: 'MVR', symbol: 'Rf', name: 'Maldivian Rufiyaa' },
    { code: 'USD', symbol: '$', name: 'US Dollar' }
];

const Settings: React.FC<Props> = ({ business, updateBusiness }) => {
  const [details, setDetails] = useState<BusinessDetails>(business);
  const [isSaved, setIsSaved] = useState(false);
  const [isGeneratingTerms, setIsGeneratingTerms] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateBusiness(details);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleLogoClick = () => {
    fileInputRef.current?.click();
  };

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setDetails(prev => ({ ...prev, logoUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLogo = (e: React.MouseEvent) => {
    e.stopPropagation();
    setDetails(prev => ({ ...prev, logoUrl: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleGenerateTerms = async () => {
    setIsGeneratingTerms(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Generate a modern, professional, and concise set of "Terms and Conditions" for a business named "${details.name || 'our company'}". 
      The terms should be formatted as a numbered list and include:
      1. Payment terms (e.g., net 7 or 30 days).
      2. Quote validity period.
      3. Brief note on cancellations or returns.
      4. Late payment interest note.
      Keep it under 150 words and sounding very professional.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });

      const generatedText = response.text;
      if (generatedText) {
        setDetails(prev => ({ ...prev, defaultTerms: generatedText.trim() }));
      }
    } catch (error) {
      console.error("Failed to generate terms:", error);
      alert("Failed to generate terms. Please check your connection.");
    } finally {
      setIsGeneratingTerms(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fadeIn">
      <header>
        <h1 className="text-3xl font-bold text-slate-900">Settings</h1>
        <p className="text-slate-500">Configure your company identity and regional preferences.</p>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-8 border-b border-slate-100 bg-slate-50/50">
            <div className="flex items-center gap-6">
                <div 
                  onClick={handleLogoClick}
                  className="group relative w-24 h-24 rounded-2xl bg-slate-200 flex items-center justify-center border-4 border-white shadow-sm overflow-hidden cursor-pointer hover:bg-slate-300 transition-all"
                >
                    {details.logoUrl ? (
                      <img src={details.logoUrl} className="w-full h-full object-cover" alt="Business Logo" />
                    ) : (
                      <i className="fa-solid fa-building text-4xl text-slate-400"></i>
                    )}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <i className="fa-solid fa-camera text-white text-xl"></i>
                    </div>
                </div>

                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*"
                  onChange={handleLogoChange}
                />

                <div>
                    <h2 className="text-xl font-bold text-slate-800">{details.name || 'Your Company Name'}</h2>
                    <p className="text-slate-500 text-sm">Update your logo and business information</p>
                    <div className="flex gap-4 mt-2">
                      <button 
                        type="button" 
                        onClick={handleLogoClick}
                        className="text-blue-600 text-sm font-semibold hover:underline flex items-center gap-1"
                      >
                        <i className="fa-solid fa-upload"></i>
                        Change Logo
                      </button>
                      {details.logoUrl && (
                        <button 
                          type="button" 
                          onClick={removeLogo}
                          className="text-red-500 text-sm font-semibold hover:underline flex items-center gap-1"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                          Remove
                        </button>
                      )}
                    </div>
                </div>
            </div>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-10">
          <section className="space-y-6">
            <h3 className="text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Business Identity</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Company Name</label>
                <input 
                    required
                    value={details.name}
                    onChange={(e) => setDetails({...details, name: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Business Email</label>
                <input 
                    required
                    type="email"
                    value={details.email}
                    onChange={(e) => setDetails({...details, email: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Phone Number</label>
                <input 
                    required
                    value={details.phone}
                    onChange={(e) => setDetails({...details, phone: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                />
                </div>
                <div className="col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Physical Address</label>
                <input 
                    required
                    value={details.address}
                    onChange={(e) => setDetails({...details, address: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">TIN Number</label>
                <input 
                    required
                    value={details.tinNumber}
                    onChange={(e) => setDetails({...details, tinNumber: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                    placeholder="Enter Tax Identification Number"
                />
                </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Regional & Taxation</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Base Currency</label>
                <select 
                    value={details.currency}
                    onChange={(e) => setDetails({...details, currency: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 font-medium"
                >
                    {CURRENCIES.map(curr => (
                        <option key={curr.code} value={curr.code}>
                            {curr.code} ({curr.symbol}) - {curr.name}
                        </option>
                    ))}
                </select>
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Default Tax Rate (%)</label>
                <div className="relative">
                    <input 
                        type="number"
                        min="0"
                        max="100"
                        step="0.01"
                        value={details.taxPercentage}
                        onChange={(e) => setDetails({...details, taxPercentage: parseFloat(e.target.value) || 0})}
                        className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 pr-10"
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">%</div>
                </div>
                <p className="mt-2 text-xs text-slate-500">Applied to subtotal in all new Invoices and Quotations.</p>
                </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Document Numbering</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Invoice Prefix</label>
                  <input 
                      required
                      value={details.invoicePrefix}
                      onChange={(e) => setDetails({...details, invoicePrefix: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                      placeholder="e.g. INV"
                  />
                  <p className="mt-2 text-xs text-slate-500">Example: {details.invoicePrefix}-1001</p>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Quotation Prefix</label>
                  <input 
                      required
                      value={details.quotationPrefix}
                      onChange={(e) => setDetails({...details, quotationPrefix: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900"
                      placeholder="e.g. QT"
                  />
                  <p className="mt-2 text-xs text-slate-500">Example: {details.quotationPrefix}-1001</p>
                </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Standard Content</h3>
            <div className="grid grid-cols-1 gap-8">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Payment Details (Bank Info)</label>
                <textarea 
                    value={details.paymentDetails}
                    onChange={(e) => setDetails({...details, paymentDetails: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 min-h-[100px]"
                    placeholder="Enter bank account name, number, etc. that will appear on your invoices..."
                />
              </div>
              <div className="relative">
                <div className="flex justify-between items-center mb-2">
                    <label className="block text-sm font-semibold text-slate-700">Default Terms & Conditions</label>
                    <button 
                        type="button"
                        disabled={isGeneratingTerms}
                        onClick={handleGenerateTerms}
                        className="text-blue-600 text-xs font-bold hover:underline flex items-center gap-1 bg-blue-50 px-3 py-1.5 rounded-lg transition-colors hover:bg-blue-100 disabled:opacity-50"
                    >
                        <i className={`fa-solid ${isGeneratingTerms ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                        {isGeneratingTerms ? 'Thinking...' : 'AI Generate Modern Terms'}
                    </button>
                </div>
                <textarea 
                    value={details.defaultTerms}
                    onChange={(e) => setDetails({...details, defaultTerms: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 min-h-[150px]"
                    placeholder="Enter standard terms that will appear on all new documents..."
                />
              </div>
            </div>
          </section>

          <div className="flex items-center justify-between pt-8 border-t border-slate-100">
            {isSaved ? (
                <span className="text-emerald-600 font-medium flex items-center gap-2 animate-bounceIn">
                    <i className="fa-solid fa-check-circle"></i> Business profile updated!
                </span>
            ) : <span className="text-slate-400 text-xs italic">* All fields are mandatory for compliant document generation</span>}
            <button 
              type="submit"
              className="px-12 py-3.5 bg-slate-900 text-white rounded-xl font-bold shadow-xl shadow-slate-200 hover:bg-black transition-all transform hover:-translate-y-1 active:translate-y-0"
            >
              Save Configuration
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useMemo } from 'react';
// Import Link from react-router-dom to fix the 'Cannot find name Link' error
import { Link } from 'react-router-dom';
import { AppState, Document, DocumentType, LineItem, CatalogItem } from '../types';
import { generatePDF } from '../utils/pdfGenerator';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  type: DocumentType;
  state: AppState;
  addDocument: (doc: Document) => void;
  updateDocument: (doc: Document) => void;
  deleteDocument: (id: string) => void;
  updateStatus: (id: string, status: any) => void;
}

const DocumentManager: React.FC<Props> = ({ type, state, addDocument, updateDocument, deleteDocument, updateStatus }) => {
  const [showModal, setShowModal] = useState(false);
  const [showCatalogModal, setShowCatalogModal] = useState(false);
  const [catalogSearchTerm, setCatalogSearchTerm] = useState('');
  const [loadingSmart, setLoadingSmart] = useState(false);
  const [editingDocId, setEditingDocId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    notes: state.business.defaultTerms || '',
    items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }] as LineItem[]
  });

  const filteredDocs = useMemo(() => {
    const docs = state.documents.filter(d => d.type === type);
    if (!searchTerm.trim()) return docs;

    const term = searchTerm.toLowerCase();
    return docs.filter(d => 
      d.number.toLowerCase().includes(term) ||
      d.clientName.toLowerCase().includes(term) ||
      d.clientEmail.toLowerCase().includes(term)
    );
  }, [state.documents, type, searchTerm]);

  const filteredCatalog = useMemo(() => {
    if (!catalogSearchTerm.trim()) return state.catalog;
    const term = catalogSearchTerm.toLowerCase();
    return state.catalog.filter(item => 
      item.description.toLowerCase().includes(term)
    );
  }, [state.catalog, catalogSearchTerm]);

  const currentSubtotal = useMemo(() => {
    return formData.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  }, [formData.items]);

  const currentTaxAmount = useMemo(() => {
    return (currentSubtotal * state.business.taxPercentage) / 100;
  }, [currentSubtotal, state.business.taxPercentage]);

  const currentTotal = currentSubtotal + currentTaxAmount;

  const resetForm = () => {
    setFormData({
      clientName: '',
      clientEmail: '',
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      notes: state.business.defaultTerms || '',
      items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }]
    });
    setEditingDocId(null);
    setShowModal(false);
  };

  const handleEdit = (doc: Document) => {
    setFormData({
      clientName: doc.clientName,
      clientEmail: doc.clientEmail,
      date: doc.date,
      dueDate: doc.dueDate,
      notes: doc.notes || '',
      items: doc.items.map(item => ({ ...item }))
    });
    setEditingDocId(doc.id);
    setShowModal(true);
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleAddFromCatalog = (catalogItem: CatalogItem) => {
    const newItem: LineItem = {
      id: Date.now().toString() + Math.random(),
      description: catalogItem.description,
      quantity: 1,
      unitPrice: catalogItem.unitPrice
    };

    setFormData(prev => {
      // If the first item is empty, replace it
      if (prev.items.length === 1 && !prev.items[0].description && prev.items[0].unitPrice === 0) {
        return { ...prev, items: [newItem] };
      }
      return { ...prev, items: [...prev.items, newItem] };
    });
    setShowCatalogModal(false);
    setCatalogSearchTerm('');
  };

  const handleRemoveItem = (id: string) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingDocId) {
      const existingDoc = state.documents.find(d => d.id === editingDocId);
      if (existingDoc) {
        const updatedDoc: Document = {
          ...existingDoc,
          clientName: formData.clientName,
          clientEmail: formData.clientEmail,
          date: formData.date,
          dueDate: formData.dueDate,
          items: formData.items,
          notes: formData.notes
        };
        updateDocument(updatedDoc);
      }
    } else {
      const prefix = type === DocumentType.QUOTATION ? state.business.quotationPrefix : state.business.invoicePrefix;
      const newDoc: Document = {
        id: Date.now().toString(),
        type,
        number: `${prefix}-${Math.floor(1000 + Math.random() * 9000)}`,
        clientName: formData.clientName,
        clientEmail: formData.clientEmail,
        date: formData.date,
        dueDate: formData.dueDate,
        items: formData.items,
        status: 'Draft',
        notes: formData.notes
      };
      addDocument(newDoc);
    }
    resetForm();
  };

  const handleSmartGenerate = async () => {
    setLoadingSmart(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Generate 3 professional service line items for a business in the ${state.business.name} industry.`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            description: { type: Type.STRING },
                            unitPrice: { type: Type.NUMBER }
                        },
                        required: ['description', 'unitPrice']
                    }
                }
            }
        });
        const items = JSON.parse(response.text || '[]');
        setFormData(prev => ({
            ...prev,
            items: items.map((it: any, idx: number) => ({
                id: `smart-${idx}-${Date.now()}`,
                description: it.description,
                quantity: 1,
                unitPrice: it.unitPrice
            }))
        }));
    } catch (err) {
        console.error("AI Error:", err);
    } finally {
        setLoadingSmart(false);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      {/* Search and Header Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">{type === DocumentType.QUOTATION ? 'Quotations' : 'Invoices'}</h1>
          <p className="text-slate-500">Manage your business documents here.</p>
        </div>
        <div className="flex w-full md:w-auto items-center gap-3">
            <div className="relative flex-1 md:w-64">
                <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
                <input 
                    type="text"
                    placeholder="Search documents..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
                />
            </div>
            <button 
                onClick={() => { resetForm(); setShowModal(true); }}
                className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-semibold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all flex items-center gap-2 whitespace-nowrap"
            >
                <i className="fa-solid fa-plus"></i>
                New {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
            </button>
        </div>
      </div>

      {/* Main Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Number</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Client</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Date</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Amount</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredDocs.length === 0 ? (
                <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                        <i className="fa-solid fa-folder-open text-4xl mb-3 block"></i>
                        No records found.
                    </td>
                </tr>
            ) : filteredDocs.map(doc => {
              const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
              const total = subtotal + (subtotal * state.business.taxPercentage / 100);
              return (
                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-semibold text-slate-900">{doc.number}</td>
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-800">{doc.clientName}</div>
                    <div className="text-xs text-slate-500">{doc.clientEmail}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{doc.date}</td>
                  <td className="px-6 py-4 font-bold text-slate-900">{state.business.currency} {total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</td>
                  <td className="px-6 py-4 text-right space-x-1">
                    <button onClick={() => handleEdit(doc)} title="Edit" className="p-2 text-amber-600 hover:bg-amber-50 rounded-lg">
                      <i className="fa-solid fa-pencil"></i>
                    </button>
                    <button onClick={() => generatePDF(doc, state.business, true)} title="View PDF" className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg">
                      <i className="fa-solid fa-eye"></i>
                    </button>
                    <button onClick={() => generatePDF(doc, state.business, false)} title="Download PDF" className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg">
                      <i className="fa-solid fa-download"></i>
                    </button>
                    {/* Only show 'Paid' action for Invoices */}
                    {type === DocumentType.INVOICE && (
                      <button onClick={() => updateStatus(doc.id, 'Paid')} title="Mark as Paid" className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg">
                        <i className="fa-solid fa-check"></i>
                      </button>
                    )}
                    <button onClick={() => deleteDocument(doc.id)} title="Delete" className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                      <i className="fa-solid fa-trash"></i>
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Main Document Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto shadow-2xl relative">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-20">
              <h2 className="text-2xl font-bold text-slate-900">
                {editingDocId ? 'Edit' : 'Create New'} {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
              </h2>
              <button onClick={() => resetForm()} className="text-slate-400 hover:text-slate-600 p-2">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Name</label>
                  <input required value={formData.clientName} onChange={(e) => setFormData({...formData, clientName: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Client Email</label>
                  <input required type="email" value={formData.clientEmail} onChange={(e) => setFormData({...formData, clientEmail: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Line Items</h3>
                    <div className="flex gap-4">
                        <button 
                            type="button"
                            onClick={() => { setCatalogSearchTerm(''); setShowCatalogModal(true); }}
                            className="text-slate-600 text-sm font-semibold hover:underline flex items-center gap-1"
                        >
                            <i className="fa-solid fa-boxes-stacked"></i>
                            Browse Catalog
                        </button>
                        <button 
                            type="button"
                            disabled={loadingSmart}
                            onClick={handleSmartGenerate}
                            className="text-blue-600 text-sm font-semibold hover:underline flex items-center gap-1"
                        >
                            <i className={`fa-solid ${loadingSmart ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                            {loadingSmart ? 'Thinking...' : 'AI Suggest Items'}
                        </button>
                    </div>
                </div>

                <div className="space-y-3">
                  {formData.items.map((item) => (
                    <div key={item.id} className="flex flex-col md:flex-row gap-4 items-start bg-slate-50 p-4 rounded-xl border border-slate-100">
                      <div className="flex-1 w-full">
                        <input placeholder="Description" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" />
                      </div>
                      <div className="w-full md:w-24">
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" />
                      </div>
                      <div className="w-full md:w-32">
                        <input type="number" value={item.unitPrice} onChange={(e) => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" />
                      </div>
                      <button type="button" onClick={() => handleRemoveItem(item.id)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                  ))}
                </div>

                <div className="flex flex-col md:flex-row justify-between items-start gap-4 pt-4">
                  <button type="button" onClick={handleAddItem} className="flex-1 w-full border-2 border-dashed border-slate-200 rounded-xl py-3 text-slate-500 font-medium hover:border-blue-400 hover:text-blue-500 transition-all">
                    <i className="fa-solid fa-plus mr-2"></i>Add Another Item
                  </button>

                  <div className="w-full md:w-72 bg-slate-900 text-white rounded-2xl p-6 shadow-xl space-y-3">
                    <div className="flex justify-between items-center text-sm text-slate-400">
                      <span>Subtotal</span>
                      <span>{state.business.currency} {currentSubtotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                    </div>
                    <div className="flex justify-between items-center text-sm text-slate-400">
                      <span>Tax ({state.business.taxPercentage}%)</span>
                      <span>{state.business.currency} {currentTaxAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                    </div>
                    <div className="pt-2 border-t border-slate-800 flex justify-between items-center">
                      <span className="text-xs font-bold uppercase tracking-widest text-slate-500">Total</span>
                      <span className="text-2xl font-black">{state.business.currency} {currentTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                    </div>
                  </div>
                </div>
              </div>

              <div className="flex justify-end gap-4 border-t border-slate-100 pt-8">
                <button type="button" onClick={() => resetForm()} className="px-6 py-3 border border-slate-200 rounded-xl font-semibold text-slate-600 hover:bg-slate-50">Cancel</button>
                <button type="submit" className="px-8 py-3 bg-blue-600 text-white rounded-xl font-bold shadow-xl shadow-blue-200 hover:bg-blue-700">
                  {editingDocId ? 'Update Document' : 'Save & Generate'}
                </button>
              </div>
            </form>

            {/* Catalog Browser Overlay Modal */}
            {showCatalogModal && (
                <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm z-30 flex items-center justify-center p-4">
                    <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden animate-slideUp flex flex-col max-h-[80vh]">
                        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
                            <h3 className="text-xl font-bold text-slate-900">Select Item from Catalog</h3>
                            <button onClick={() => setShowCatalogModal(false)} className="text-slate-400 hover:text-slate-600">
                                <i className="fa-solid fa-xmark"></i>
                            </button>
                        </div>

                        <div className="p-4 bg-slate-50 border-b border-slate-100">
                          <div className="relative">
                            <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
                            <input 
                              autoFocus
                              type="text" 
                              placeholder="Search catalog items..."
                              value={catalogSearchTerm}
                              onChange={(e) => setCatalogSearchTerm(e.target.value)}
                              className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 shadow-sm text-sm"
                            />
                          </div>
                        </div>

                        <div className="flex-1 overflow-y-auto">
                            {state.catalog.length === 0 ? (
                                <div className="p-12 text-center text-slate-400">
                                    <p className="mb-4">No items in your catalog yet.</p>
                                    <Link to="/catalog" className="text-blue-600 font-bold hover:underline" onClick={() => setShowCatalogModal(false)}>
                                        Go to Catalog Manager
                                    </Link>
                                </div>
                            ) : filteredCatalog.length === 0 ? (
                                <div className="p-12 text-center text-slate-400">
                                    <p>No catalog items match "{catalogSearchTerm}"</p>
                                </div>
                            ) : (
                                <div className="divide-y divide-slate-100">
                                    {filteredCatalog.map(item => (
                                        <button 
                                            key={item.id}
                                            type="button"
                                            onClick={() => handleAddFromCatalog(item)}
                                            className="w-full text-left p-4 hover:bg-blue-50 transition-colors group flex justify-between items-center"
                                        >
                                            <div>
                                                <div className="font-semibold text-slate-800 group-hover:text-blue-700">{item.description}</div>
                                                <div className="text-sm text-slate-500">{state.business.currency} {item.unitPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}</div>
                                            </div>
                                            <i className="fa-solid fa-plus text-slate-300 group-hover:text-blue-500"></i>
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                        <div className="p-4 border-t border-slate-100 bg-slate-50 text-center">
                          <p className="text-xs text-slate-400">Tip: Predefined items help you build documents faster.</p>
                        </div>
                    </div>
                </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default DocumentManager;

import React, { useState, useMemo } from 'react';
// Import Link from react-router-dom to fix the 'Cannot find name Link' error
import { Link } from 'react-router-dom';
import { AppState, Document, DocumentType, LineItem, CatalogItem } from '../types';
import { generatePDF } from '../utils/pdfGenerator';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  type: DocumentType;
  state: AppState;
  addDocument: (doc: Document) => void;
  updateDocument: (doc: Document) => void;
  deleteDocument: (id: string) => void;
  updateStatus: (id: string, status: any) => void;
}

const DocumentManager: React.FC<Props> = ({ type, state, addDocument, updateDocument, deleteDocument, updateStatus }) => {
  const [showModal, setShowModal] = useState(false);
  const [showCatalogModal, setShowCatalogModal] = useState(false);
  const [catalogSearchTerm, setCatalogSearchTerm] = useState('');
  const [loadingSmart, setLoadingSmart] = useState(false);
  const [editingDocId, setEditingDocId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    notes: state.business.defaultTerms || '',
    items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }] as LineItem[]
  });

  const filteredDocs = useMemo(() => {
    const docs = state.documents.filter(d => d.type === type);
    if (!searchTerm.trim()) return docs;

    const term = searchTerm.toLowerCase();
    return docs.filter(d => 
      d.number.toLowerCase().includes(term) ||
      d.clientName.toLowerCase().includes(term) ||
      d.clientEmail.toLowerCase().includes(term)
    );
  }, [state.documents, type, searchTerm]);

  const filteredCatalog = useMemo(() => {
    if (!catalogSearchTerm.trim()) return state.catalog;
    const term = catalogSearchTerm.toLowerCase();
    return state.catalog.filter(item => 
      item.description.toLowerCase().includes(term)
    );
  }, [state.catalog, catalogSearchTerm]);

  const currentSubtotal = useMemo(() => {
    return formData.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  }, [formData.items]);

  const currentTaxAmount = useMemo(() => {
    return (currentSubtotal * state.business.taxPercentage) / 100;
  }, [currentSubtotal, state.business.taxPercentage]);

  const currentTotal = currentSubtotal + currentTaxAmount;

  const formatDateDisplay = (dateStr: string) => {
    if (!dateStr) return '';
    return dateStr.split('-').reverse().join('-');
  };

  const resetForm = () => {
    setFormData({
      clientName: '',
      clientEmail: '',
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      notes: state.business.defaultTerms || '',
      items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }]
    });
    setEditingDocId(null);
    setShowModal(false);
  };

  const handleEdit = (doc: Document) => {
    setFormData({
      clientName: doc.clientName,
      clientEmail: doc.clientEmail,
      date: doc.date,
      dueDate: doc.dueDate,
      notes: doc.notes || '',
      items: doc.items.map(item => ({ ...item }))
    });
    setEditingDocId(doc.id);
    setShowModal(true);
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleAddFromCatalog = (catalogItem: CatalogItem) => {
    const newItem: LineItem = {
      id: Date.now().toString() + Math.random(),
      description: catalogItem.description,
      quantity: 1,
      unitPrice: catalogItem.unitPrice
    };

    setFormData(prev => {
      // If the first item is empty, replace it
      if (prev.items.length === 1 && !prev.items[0].description && prev.items[0].unitPrice === 0) {
        return { ...prev, items: [newItem] };
      }
      return { ...prev, items: [...prev.items, newItem] };
    });
    setShowCatalogModal(false);
    setCatalogSearchTerm('');
  };

  const handleRemoveItem = (id: string) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingDocId) {
      const existingDoc = state.documents.find(d => d.id === editingDocId);
      if (existingDoc) {
        const updatedDoc: Document = {
          ...existingDoc,
          clientName: formData.clientName,
          clientEmail: formData.clientEmail,
          date: formData.date,
          dueDate: formData.dueDate,
          items: formData.items,
          notes: formData.notes
        };
        updateDocument(updatedDoc);
      }
    } else {
      const prefix = type === DocumentType.QUOTATION ? state.business.quotationPrefix : state.business.invoicePrefix;
      const newDoc: Document = {
        id: Date.now().toString(),
        type,
        number: `${prefix}-${Math.floor(1000 + Math.random() * 9000)}`,
        clientName: formData.clientName,
        clientEmail: formData.clientEmail,
        date: formData.date,
        dueDate: formData.dueDate,
        items: formData.items,
        status: 'Draft',
        notes: formData.notes
      };
      addDocument(newDoc);
    }
    resetForm();
  };

  const handleSmartGenerate = async () => {
    setLoadingSmart(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Generate 3 professional service line items for a business in the ${state.business.name} industry.`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            description: { type: Type.STRING },
                            unitPrice: { type: Type.NUMBER }
                        },
                        required: ['description', 'unitPrice']
                    }
                }
            }
        });
        const items = JSON.parse(response.text || '[]');
        setFormData(prev => ({
            ...prev,
            items: items.map((it: any, idx: number) => ({
                id: `smart-${idx}-${Date.now()}`,
                description: it.description,
                quantity: 1,
                unitPrice: it.unitPrice
            }))
        }));
    } catch (err) {
        console.error("AI Error:", err);
    } finally {
        setLoadingSmart(false);
    }
  };

  return (
    <div className="space-y-6 animate-fadeIn">
      {/* Search and Header Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">{type === DocumentType.QUOTATION ? 'Quotations' : 'Invoices'}</h1>
          <p className="text-slate-500">Manage your business documents here.</p>
        </div>
        <div className="flex w-full md:w-auto items-center gap-3">
            <div className="relative flex-1 md:w-64">
                <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
                <input 
                    type="text"
                    placeholder="Search documents..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 shadow-sm"
                />
            </div>
            <button 
                onClick={() => { resetForm(); setShowModal(true); }}
                className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-semibold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all flex items-center gap-2 whitespace-nowrap"
            >
                <i className="fa-solid fa-plus"></i>
                New {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
            </button>
        </div>
      </div>

      {/* Main Table */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Number</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Client</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Date</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase">Amount</th>
              <th className="px-6 py-4 text-sm font-semibold text-slate-600 uppercase text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredDocs.length === 0 ? (
                <tr>
                    <td colSpan={5} className="px-6 py-12 text-center text-slate-400">
                        <i className="fa-solid fa-folder-open text-4xl mb-3 block"></i>
                        No records found.
                    </td>
                </tr>
            ) : filteredDocs.map(doc => {
              const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
              const total = subtotal + (subtotal * state.business.taxPercentage / 100);
              return (
                <tr key={doc.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 font-semibold text-slate-900">{doc.number}</td>
                  <td className="px-6 py-4">
                    <div className="font-medium text-slate-800">{doc.clientName}</div>
                    <div className="text-xs text-slate-500">{doc.clientEmail}</div>
                  </td>
                  <td className="px-6 py-4 text-slate-600">{formatDateDisplay(doc.date)}</td>
                  <td className="px-6 py-4 font-bold text-slate-900">{state.business.currency} {total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</td>
                  <td className="px-6 py-4 text-right space-x-1">
                    <button onClick={() => handleEdit(doc)} title="Edit" className="p-2 text-amber-600 hover:bg-amber-50 rounded-lg">
                      <i className="fa-solid fa-pencil"></i>
                    </button>
                    <button onClick={() => generatePDF(doc, state.business, true)} title="View PDF" className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg">
                      <i className="fa-solid fa-eye"></i>
                    </button>
                    <button onClick={() => generatePDF(doc, state.business, false)} title="Download PDF" className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg">
                      <i className="fa-solid fa-download"></i>
                    </button>
                    {/* Only show 'Paid' action for Invoices */}
                    {type === DocumentType.INVOICE && (
                      <button onClick={() => updateStatus(doc.id, 'Paid')} title="Mark as Paid" className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg">
                        <i className="fa-solid fa-check"></i>
                      </button>
                    )}
                    <button onClick={() => deleteDocument(doc.id)} title="Delete" className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                      <i className="fa-solid fa-trash"></i>
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Main Document Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto shadow-2xl relative">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-20">
              <h2 className="text-2xl font-bold text-slate-900">
                {editingDocId ? 'Edit' : 'Create New'} {type === DocumentType.QUOTATION ? 'Quotation' : 'Invoice'}
              </h2>
              <button onClick={() => resetForm()} className="text-slate-400 hover:text-slate-600 p-2">
                <i className="fa-solid fa-xmark text-xl"></i>
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="grid grid-cols-1 gap-4">
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Client Name</label>
                    <input required value={formData.clientName} onChange={(e) => setFormData({...formData, clientName: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Client Email</label>
                    <input required type="email" value={formData.clientEmail} onChange={(e) => setFormData({...formData, clientEmail: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" />
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Date</label>
                    <input type="date" value={formData.date} onChange={(e) => setFormData({...formData, date: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" />
                  </div>
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Due Date</label>
                    <input type="date" value={formData.dueDate} onChange={(e) => setFormData({...formData, dueDate: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900" />
                  </div>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-bold text-slate-800">Line Items</h3>
                    <div className="flex gap-4">
                        <button 
                            type="button"
                            onClick={() => { setCatalogSearchTerm(''); setShowCatalogModal(true); }}
                            className="text-slate-600 text-sm font-semibold hover:underline flex items-center gap-1"
                        >
                            <i className="fa-solid fa-boxes-stacked"></i>
                            Browse Catalog
                        </button>
                        <button 
                            type="button"
                            disabled={loadingSmart}
                            onClick={handleSmartGenerate}
                            className="text-blue-600 text-sm font-semibold hover:underline flex items-center gap-1"
                        >
                            <i className={`fa-solid ${loadingSmart ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                            {loadingSmart ? 'Thinking...' : 'AI Suggest Items'}
                        </button>
                    </div>
                </div>

                <div className="space-y-3">
                  {formData.items.map((item) => (
                    <div key={item.id} className="flex flex-col md:flex-row gap-4 items-start bg-slate-50 p-4 rounded-xl border border-slate-100">
                      <div className="flex-1 w-full">
                        <input placeholder="Description" value={item.description} onChange={(e) => handleItemChange(item.id, 'description', e.target.value)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" />
                      </div>
                      <div className="w-full md:w-24">
                        <input type="number" value={item.quantity} onChange={(e) => handleItemChange(item.id, 'quantity', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" />
                      </div>
                      <div className="w-full md:w-32">
                        <input type="number" value={item.unitPrice} onChange={(e) => handleItemChange(item.id, 'unitPrice', parseFloat(e.target.value) || 0)} className="w-full bg-white border border-slate-200 rounded-lg px-3 py-2 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900" />
                      </div>
                      <button type="button" onClick={() => handleRemoveItem(item.id)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
