import React, { useState, useMemo } from 'react';
import { AppState, CatalogItem } from '../types';

interface Props {
  state: AppState;
  addItem: (item: CatalogItem) => void;
  updateItem: (item: CatalogItem) => void;
  deleteItem: (id: string) => void;
}

const CatalogManager: React.FC<Props> = ({ state, addItem, updateItem, deleteItem }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [formData, setFormData] = useState({
    description: '',
    unitPrice: 0
  });

  const filteredItems = useMemo(() => {
    if (!searchTerm.trim()) return state.catalog;
    const term = searchTerm.toLowerCase();
    return state.catalog.filter(i => 
      i.description.toLowerCase().includes(term)
    );
  }, [state.catalog, searchTerm]);

  const resetForm = () => {
    setFormData({ description: '', unitPrice: 0 });
    setEditingId(null);
    setShowModal(false);
  };

  const handleEdit = (item: CatalogItem) => {
    setFormData({
      description: item.description,
      unitPrice: item.unitPrice
    });
    setEditingId(item.id);
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      updateItem({ id: editingId, ...formData });
    } else {
      addItem({ id: Date.now().toString(), ...formData });
    }
    resetForm();
  };

  return (
    <div className="space-y-6 animate-fadeIn pb-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Item Catalog</h1>
          <p className="text-sm text-slate-500">Manage your products and services.</p>
        </div>
        <div className="flex flex-col sm:flex-row w-full md:w-auto items-stretch sm:items-center gap-3">
          <div className="relative flex-1 md:w-64">
            <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
            <input 
              type="text"
              placeholder="Search catalog..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500 shadow-sm text-sm"
            />
          </div>
          <button 
            onClick={() => { resetForm(); setShowModal(true); }}
            className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-semibold hover:bg-black transition-all flex items-center justify-center gap-2 whitespace-nowrap text-sm"
          >
            <i className="fa-solid fa-plus"></i>
            New Item
          </button>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left min-w-[500px]">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-xs font-semibold text-slate-600 uppercase">Description</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-600 uppercase">Standard Price</th>
                <th className="px-6 py-4 text-xs font-semibold text-slate-600 uppercase text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredItems.length === 0 ? (
                <tr>
                  <td colSpan={3} className="px-6 py-12 text-center text-slate-400">
                    <i className="fa-solid fa-box-open text-4xl mb-3 block"></i>
                    {searchTerm ? 'No matches.' : 'Catalog is empty.'}
                  </td>
                </tr>
              ) : filteredItems.map(item => (
                <tr key={item.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-6 py-4 font-medium text-slate-800 text-sm">{item.description}</td>
                  <td className="px-6 py-4 font-bold text-slate-900 text-sm">
                    {state.business.currency} {item.unitPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                  </td>
                  <td className="px-6 py-4 text-right space-x-2 whitespace-nowrap">
                    <button onClick={() => handleEdit(item)} className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg">
                      <i className="fa-solid fa-pencil"></i>
                    </button>
                    <button onClick={() => deleteItem(item.id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                      <i className="fa-solid fa-trash"></i>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
            <div className="p-5 md:p-6 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-lg md:text-xl font-bold text-slate-900">{editingId ? 'Edit' : 'Create'} Item</h2>
              <button onClick={() => resetForm()} className="text-slate-400 hover:text-slate-600 p-2">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-5 md:p-6 space-y-5">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Item Description</label>
                <input 
                  required
                  value={formData.description}
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm" 
                  placeholder="Service or product name..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Unit Price ({state.business.currency})</label>
                <input 
                  required
                  type="number"
                  step="0.01"
                  value={formData.unitPrice}
                  onChange={(e) => setFormData({...formData, unitPrice: parseFloat(e.target.value) || 0})}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm" 
                />
              </div>
              <div className="flex justify-end gap-3 pt-4">
                <button type="button" onClick={() => resetForm()} className="px-5 py-2.5 border border-slate-200 rounded-xl text-slate-600 font-semibold hover:bg-slate-50 text-sm">
                  Cancel
                </button>
                <button type="submit" className="px-8 py-2.5 bg-blue-600 text-white rounded-xl font-bold shadow-lg shadow-blue-100 hover:bg-blue-700 text-sm">
                  {editingId ? 'Update' : 'Add Item'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CatalogManager;

export enum DocumentType {
  QUOTATION = 'QUOTATION',
  INVOICE = 'INVOICE'
}

export enum TransactionType {
  SALE = 'SALE',
  EXPENSE = 'EXPENSE'
}

export interface BusinessDetails {
  name: string;
  email: string;
  phone: string;
  address: string;
  tinNumber: string;
  currency: string;
  taxPercentage: number;
  invoicePrefix: string;
  quotationPrefix: string;
  logoUrl?: string;
  defaultTerms?: string;
  paymentDetails?: string;
}

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface CatalogItem {
  id: string;
  description: string;
  unitPrice: number;
}

export interface Client {
  id: string;
  name: string;
  email: string;
  phone: string;
  address: string;
}

export interface Document {
  id: string;
  type: DocumentType;
  number: string;
  date: string;
  dueDate: string;
  clientName: string;
  clientEmail: string;
  items: LineItem[];
  status: 'Draft' | 'Sent' | 'Paid' | 'Expired';
  notes?: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  date: string;
  category: string;
  amount: number;
  description: string;
  reference?: string;
}

export interface AppState {
  business: BusinessDetails;
  documents: Document[];
  transactions: Transaction[];
  catalog: CatalogItem[];
  clients: Client[];
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import CatalogManager from './components/CatalogManager';
import ClientManager from './components/ClientManager';
import Settings from './components/Settings';
import { AppState, DocumentType, TransactionType, Document, Transaction, CatalogItem, Client } from './types';

const INITIAL_STATE: AppState = {
  business: {
    name: 'SANDPIX MALDIVES',
    email: 'info@sandpixmaldives.com',
    phone: '+960 797 3617',
    address: 'Blue House, HDh. Nellaidhoo, Maldives',
    tinNumber: '1106645GST501',
    currency: 'MVR',
    taxPercentage: 8,
    invoicePrefix: 'INV',
    quotationPrefix: 'QT',
    defaultTerms: '1. Please pay within 7 days.\n2. Goods once sold are not returnable.',
    paymentDetails: 'Bank: Bank of Maldives (BML)\nAccount Name: SANDPIX MALDIVES\nAccount Number: 7730000000001\nBranch: Main Branch'
  },
  documents: [],
  transactions: [],
  catalog: [],
  clients: []
};

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('bizflow_state');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Migrations
      if (!parsed.catalog) parsed.catalog = [];
      if (!parsed.clients) parsed.clients = [];
      if (!parsed.business.invoicePrefix) parsed.business.invoicePrefix = 'INV';
      if (!parsed.business.quotationPrefix) parsed.business.quotationPrefix = 'QT';
      return parsed;
    }
    return INITIAL_STATE;
  });

  useEffect(() => {
    localStorage.setItem('bizflow_state', JSON.stringify(state));
  }, [state]);

  const updateBusiness = (business: AppState['business']) => {
    setState(prev => ({ ...prev, business }));
  };

  const addDocument = (doc: Document) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
  };

  const updateDocument = (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => d.id === doc.id ? doc : d)
    }));
  };

  const updateDocumentStatus = (id: string, status: 'Draft' | 'Sent' | 'Paid' | 'Expired') => {
      setState(prev => {
          const doc = prev.documents.find(d => d.id === id);
          if (!doc) return prev;

          let newTransactions = prev.transactions;
          if (doc.type === DocumentType.INVOICE && status === 'Paid' && doc.status !== 'Paid') {
              const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
              const taxAmount = (subtotal * prev.business.taxPercentage) / 100;
              const total = subtotal + taxAmount;

              const newSale: Transaction = {
                  id: `sale-inv-${doc.id}-${Date.now()}`,
                  type: TransactionType.SALE,
                  date: new Date().toISOString().split('T')[0],
                  category: 'Product Sales',
                  amount: total,
                  description: `Payment for Invoice ${doc.number}`,
                  reference: doc.number
              };
              newTransactions = [newSale, ...prev.transactions];
          }

          return {
              ...prev,
              documents: prev.documents.map(d => d.id === id ? { ...d, status } : d),
              transactions: newTransactions
          };
      });
  };

  const deleteDocument = (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
  };

  const addTransaction = (tx: Transaction) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
  };

  const deleteTransaction = (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
  };

  const addCatalogItem = (item: CatalogItem) => {
    setState(prev => ({ ...prev, catalog: [item, ...prev.catalog] }));
  };

  const updateCatalogItem = (item: CatalogItem) => {
    setState(prev => ({
      ...prev,
      catalog: prev.catalog.map(i => i.id === item.id ? item : i)
    }));
  };

  const deleteCatalogItem = (id: string) => {
    setState(prev => ({ ...prev, catalog: prev.catalog.filter(i => i.id !== id) }));
  };

  const addClient = (client: Client) => {
    setState(prev => ({ ...prev, clients: [client, ...prev.clients] }));
  };

  const updateClient = (client: Client) => {
    setState(prev => ({
      ...prev,
      clients: prev.clients.map(c => c.id === client.id ? client : c)
    }));
  };

  const deleteClient = (id: string) => {
    setState(prev => ({ ...prev, clients: prev.clients.filter(c => c.id !== id) }));
  };

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden relative">
        <Sidebar isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} />

        <div className="flex-1 flex flex-col min-w-0">
          {/* Mobile Header */}
          <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-1.5 rounded-lg text-white">
                <i className="fa-solid fa-bolt text-xs"></i>
              </div>
              <h1 className="font-bold text-slate-900 tracking-tight">Invoice ME</h1>
            </div>
            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
              aria-label="Open menu"
            >
              <i className="fa-solid fa-bars text-xl"></i>
            </button>
          </header>

          <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <Routes>
              <Route path="/" element={<Dashboard state={state} />} />
              <Route 
                path="/quotations" 
                element={<DocumentManager 
                  type={DocumentType.QUOTATION} 
                  state={state} 
                  addDocument={addDocument}
                  updateDocument={updateDocument}
                  deleteDocument={deleteDocument}
                  updateStatus={updateDocumentStatus}
                />} 
              />
              <Route 
                path="/invoices" 
                element={<DocumentManager 
                  type={DocumentType.INVOICE} 
                  state={state} 
                  addDocument={addDocument}
                  updateDocument={updateDocument}
                  deleteDocument={deleteDocument}
                  updateStatus={updateDocumentStatus}
                />} 
              />
              <Route 
                path="/clients" 
                element={<ClientManager 
                  state={state} 
                  addClient={addClient}
                  updateClient={updateClient}
                  deleteClient={deleteClient}
                />} 
              />
              <Route 
                path="/catalog" 
                element={<CatalogManager 
                  state={state} 
                  addItem={addCatalogItem}
                  updateItem={updateCatalogItem}
                  deleteItem={deleteCatalogItem}
                />} 
              />
              <Route 
                path="/sales" 
                element={<TransactionManager 
                  type={TransactionType.SALE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction}
                />} 
              />
              <Route 
                path="/expenses" 
                element={<TransactionManager 
                  type={TransactionType.EXPENSE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction}
                />} 
              />
              <Route 
                path="/settings" 
                element={<Settings business={state.business} updateBusiness={updateBusiness} />} 
              />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

