  pdf.setTextColor(...accentColor);
  const metaY = Math.max(margin, currentY - 20); 
  pdf.text(doc.type.toUpperCase(), rightAlignX, metaY + 5, { align: 'right' });

  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text(`NO: ${doc.number}`, rightAlignX, metaY + 12, { align: 'right' });

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(`Issue Date: ${formatDateDisplay(doc.date)}`, rightAlignX, metaY + 18, { align: 'right' });
  pdf.text(`Due Date: ${formatDateDisplay(doc.dueDate)}`, rightAlignX, metaY + 23, { align: 'right' });

  // 4. Header Section - Business Info (Left)
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(18);
  pdf.setTextColor(...secondaryColor);
  pdf.text(business.name.toUpperCase(), margin, currentY + 5);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);

  const addressLines = pdf.splitTextToSize(business.address, 75);
  pdf.text(addressLines, margin, currentY + 12);

  const addressHeight = addressLines.length * 5;
  const contactY = currentY + 12 + addressHeight;

  pdf.text(`Email: ${business.email}`, margin, contactY);
  pdf.text(`Phone: ${business.phone}`, margin, contactY + 5);
  pdf.setFont('helvetica', 'bold');
  pdf.setTextColor(...secondaryColor);
  pdf.text(`TIN Number: ${business.tinNumber}`, margin, contactY + 10);

  const headerEndRight = metaY + 23;
  const headerEndLeft = contactY + 10;
  currentY = Math.max(headerEndRight, headerEndLeft) + 10;

  pdf.setDrawColor(241, 245, 249); 
  pdf.line(margin, currentY, pageWidth - margin, currentY);

  // 6. Bill To Section
  currentY += 10;
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('BILL TO', margin, currentY);

  pdf.setFontSize(12);
  pdf.text(doc.clientName, margin, currentY + 7);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(doc.clientEmail, margin, currentY + 13);

  // 7. Main Table
  const tableHeaders = [['DESCRIPTION', 'QTY', 'UNIT PRICE', 'TOTAL']];
  const tableData = doc.items.map(item => [
    item.description,
    item.quantity.toString(),
    `${business.currency} ${item.unitPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}`,
    `${business.currency} ${(item.quantity * item.unitPrice).toLocaleString(undefined, { minimumFractionDigits: 2 })}`
  ]);

  const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  const taxAmount = (subtotal * business.taxPercentage) / 100;
  const total = subtotal + taxAmount;

  autoTable(pdf, {
    startY: currentY + 25,
    head: tableHeaders,
    body: tableData,
    theme: 'plain',
    headStyles: { 
      fillColor: [248, 250, 252],
      textColor: secondaryColor,
      fontStyle: 'bold',
      fontSize: 9,
      cellPadding: 4,
    },
    bodyStyles: { 
      fontSize: 9,
      textColor: secondaryColor,
      cellPadding: 4
    },
    columnStyles: {
      0: { halign: 'left' },
      1: { halign: 'center', cellWidth: 20 },
      2: { halign: 'right', cellWidth: 45 },
      3: { halign: 'right', fontStyle: 'bold', cellWidth: 45 }
    },
    margin: { left: margin, right: margin },
    didParseCell: (data) => {
      if (data.section === 'head') {
        const colIndex = data.column.index;
        if (colIndex === 1) data.cell.styles.halign = 'center';
        if (colIndex === 2 || colIndex === 3) data.cell.styles.halign = 'right';
      }
    },
    didDrawCell: (data) => {
        if (data.section === 'body') {
            pdf.setDrawColor(241, 245, 249);
            pdf.line(data.cell.x, data.cell.y + data.cell.height, data.cell.x + data.cell.width, data.cell.y + data.cell.height);
        }
    }
  });

  // 8. Summary Block
  const summaryY = ((pdf as any).lastAutoTable?.finalY || 150) + 15;
  const summaryX = pageWidth - margin;
  const labelX = pageWidth - margin - 90; 

  // Watermark drawn BEFORE text to be "behind"
  if (doc.status === 'Paid') {
    pdf.saveGraphicsState();
    const GState = (pdf as any).GState;
    if (GState) {
        pdf.setGState(new GState({ opacity: 0.12 })); // Slightly increased opacity for visibility but kept subtle
    }
    pdf.setFontSize(65);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(16, 185, 129); // emerald-500 for a fresh stamp look

    // Positioned centered relative to the total section area
    pdf.text('PAID', pageWidth * 0.7, summaryY + 15, { 
      angle: 12, 
      align: 'center'
    });
    pdf.restoreGraphicsState();
  }

  // Draw Summary Text (will appear over the watermark because it's drawn after)
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);

  pdf.text('Subtotal:', labelX, summaryY);
  pdf.text(`${business.currency} ${subtotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, summaryY, { align: 'right' });

  pdf.text(`Tax (${business.taxPercentage}%):`, labelX, summaryY + 8);
  pdf.text(`${business.currency} ${taxAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, summaryY + 8, { align: 'right' });

  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('TOTAL AMOUNT:', labelX, summaryY + 22);

  pdf.setFontSize(16);
  pdf.setTextColor(...accentColor);
  pdf.text(`${business.currency} ${total.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, summaryY + 22, { align: 'right' });

  let footerContentY = summaryY + 45;

  if (doc.notes) {
    pdf.setFont('helvetica', 'bold');
    pdf.setFontSize(9);
    pdf.setTextColor(...secondaryColor);
    pdf.text('NOTES & TERMS', margin, footerContentY);

    pdf.setFont('helvetica', 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(...lightGray);
    const splitNotes = pdf.splitTextToSize(doc.notes, pageWidth - (2 * margin));
    pdf.text(splitNotes, margin, footerContentY + 5);
    footerContentY += (splitNotes.length * 4) + 12;
  }

  if (business.paymentDetails) {
    pdf.setFont('helvetica', 'bold');
    pdf.setFontSize(9);
    pdf.setTextColor(...secondaryColor);
    pdf.text('PAYMENT DETAILS', margin, footerContentY);

    pdf.setFont('helvetica', 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(...lightGray);
    const splitPayment = pdf.splitTextToSize(business.paymentDetails, pageWidth - (2 * margin));
    pdf.text(splitPayment, margin, footerContentY + 5);
  }

  // 9. Modern Geometric Footer Pattern with 30% Transparency - Fixed drawing logic
  const footerHeight = 20;
  const patternOpacity = 0.3;

  pdf.saveGraphicsState();
  const GState = (pdf as any).GState;
  if (GState) {
      pdf.setGState(new GState({ opacity: patternOpacity }));
  }

  // Background Block (Full Width)
  pdf.setFillColor(...lightBlue);
  pdf.rect(0, pageHeight - footerHeight, pageWidth, footerHeight, 'F');

  // Geometric Accent: Slanted Block on Left
  pdf.setFillColor(...accentColor);
  pdf.rect(0, pageHeight - footerHeight, pageWidth * 0.20, footerHeight, 'F');
  pdf.triangle(
      pageWidth * 0.20, pageHeight - footerHeight,
      pageWidth * 0.25, pageHeight,
      pageWidth * 0.20, pageHeight,
      'F'
  );

  // Geometric Accent: Triangle on Right
  pdf.setFillColor(...secondaryColor);
  pdf.triangle(
      pageWidth, pageHeight,
      pageWidth * 0.70, pageHeight,
      pageWidth, pageHeight - footerHeight,
      'F'
  );

  // Thin Accent Top Line
  pdf.setDrawColor(...accentColor);
  pdf.setLineWidth(0.5);
  pdf.line(0, pageHeight - footerHeight, pageWidth, pageHeight - footerHeight);

  pdf.restoreGraphicsState();

  // Footer Text - Center Aligned
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(7);
  pdf.setTextColor(...secondaryColor);
  pdf.text(`${business.name.toUpperCase()}  |  TIN: ${business.tinNumber}`, pageWidth / 2, pageHeight - 6, { align: 'center' });

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(7);
  pdf.setTextColor(...lightGray);
  pdf.text(`This is a computer generated document.`, pageWidth / 2, pageHeight - 12, { align: 'center' });

  if (viewMode) {
    const blobURL = pdf.output('bloburl');
    window.open(blobURL as any, '_blank');
  } else {
    pdf.save(`${doc.type}_${doc.number}.pdf`);
  }
};

import React, { useState, useRef } from 'react';
import { BusinessDetails } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  business: BusinessDetails;
  updateBusiness: (details: BusinessDetails) => void;
}

const CURRENCIES = [
    { code: 'MVR', symbol: 'Rf', name: 'Maldivian Rufiyaa' },
    { code: 'USD', symbol: '$', name: 'US Dollar' },
    { code: 'EUR', symbol: '€', name: 'Euro' },
    { code: 'GBP', symbol: '£', name: 'British Pound' },
    { code: 'INR', symbol: '₹', name: 'Indian Rupee' },
    { code: 'AED', symbol: 'DH', name: 'UAE Dirham' }
];

const Settings: React.FC<Props> = ({ business, updateBusiness }) => {
  const [details, setDetails] = useState<BusinessDetails>(business);
  const [isSaved, setIsSaved] = useState(false);
  const [isGeneratingTerms, setIsGeneratingTerms] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateBusiness(details);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleLogoClick = () => {
    fileInputRef.current?.click();
  };

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setDetails(prev => ({ ...prev, logoUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLogo = (e: React.MouseEvent) => {
    e.stopPropagation();
    setDetails(prev => ({ ...prev, logoUrl: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleGenerateTerms = async () => {
    setIsGeneratingTerms(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Generate a modern, professional, and concise set of "Terms and Conditions" for a business named "${details.name || 'our company'}". 
      The terms should be formatted as a numbered list and include:
      1. Payment terms (e.g., net 7 or 30 days).
      2. Quote validity period.
      3. Brief note on cancellations or returns.
      4. Late payment interest note.
      Keep it under 150 words and sounding very professional.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });

      const generatedText = response.text;
      if (generatedText) {
        setDetails(prev => ({ ...prev, defaultTerms: generatedText.trim() }));
      }
    } catch (error) {
      console.error("Failed to generate terms:", error);
    } finally {
      setIsGeneratingTerms(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 md:space-y-8 animate-fadeIn pb-12">
      <header>
        <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Settings</h1>
        <p className="text-sm text-slate-500">Configure your company identity and regional preferences.</p>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 md:p-8 border-b border-slate-100 bg-slate-50/50">
            <div className="flex flex-col sm:flex-row items-center gap-6">
                <div 
                  onClick={handleLogoClick}
                  className="group relative w-24 h-24 rounded-2xl bg-slate-200 flex items-center justify-center border-4 border-white shadow-sm overflow-hidden cursor-pointer hover:bg-slate-300 transition-all shrink-0"
                >
                    {details.logoUrl ? (
                      <img src={details.logoUrl} className="w-full h-full object-cover" alt="Business Logo" />
                    ) : (
                      <i className="fa-solid fa-building text-4xl text-slate-400"></i>
                    )}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <i className="fa-solid fa-camera text-white text-xl"></i>
                    </div>
                </div>

                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*"
                  onChange={handleLogoChange}
                />

                <div className="text-center sm:text-left">
                    <h2 className="text-xl font-bold text-slate-800 truncate max-w-[250px] md:max-w-md">{details.name || 'Your Company Name'}</h2>
                    <p className="text-slate-500 text-sm">Update your logo and business information</p>
                    <div className="flex justify-center sm:justify-start gap-4 mt-3">
                      <button 
                        type="button" 
                        onClick={handleLogoClick}
                        className="text-blue-600 text-xs font-semibold hover:underline flex items-center gap-1"
                      >
                        <i className="fa-solid fa-upload"></i>
                        Change Logo
                      </button>
                      {details.logoUrl && (
                        <button 
                          type="button" 
                          onClick={removeLogo}
                          className="text-red-500 text-xs font-semibold hover:underline flex items-center gap-1"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                          Remove
                        </button>
                      )}
                    </div>
                </div>
            </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-10">
          <section className="space-y-6">
            <h3 className="text-base md:text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Business Identity</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 md:gap-6">
                <div className="col-span-1 md:col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Company Name</label>
                <input 
                    required
                    value={details.name}
                    onChange={(e) => setDetails({...details, name: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Business Email</label>
                <input 
                    required
                    type="email"
