        // If no business data found (first time), use initial state but try to insert it
        let activeBusiness = businessData || INITIAL_STATE.business;
        if (!businessData && !bizError) {
           await supabase.from('business_settings').insert({ id: 1, ...INITIAL_STATE.business });
        }

        setState({
          business: activeBusiness,
          documents: docsData || [],
          transactions: txsData || [],
          catalog: catalogData || [],
          clients: clientsData || []
        });
      } catch (err) {
        console.error("Failed to fetch data from Supabase:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchAllData();
  }, []);

  const updateBusiness = async (business: BusinessDetails) => {
    // 1. Update UI state immediately
    setState(prev => ({ ...prev, business }));

    // 2. Persist to Supabase
    const { error } = await supabase
      .from('business_settings')
      .upsert({ id: 1, ...business }, { onConflict: 'id' });

    if (error) {
      console.error("Error updating business settings:", error);
      alert("Failed to sync settings. Please check your connection.");
    }
  };

  const addDocument = async (doc: Document) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
    await supabase.from('documents').insert(doc);
  };

  const updateDocument = async (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => d.id === doc.id ? doc : d)
    }));
    await supabase.from('documents').update(doc).eq('id', doc.id);
  };

  const updateDocumentStatus = async (id: string, status: 'Draft' | 'Sent' | 'Paid' | 'Expired') => {
      const doc = state.documents.find(d => d.id === id);
      if (!doc) return;

      let newTransaction: Transaction | null = null;
      if (doc.type === DocumentType.INVOICE && status === 'Paid' && doc.status !== 'Paid') {
          const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
          const taxAmount = (subtotal * state.business.taxPercentage) / 100;
          const total = subtotal + taxAmount;

          newTransaction = {
              id: `sale-inv-${doc.id}-${Date.now()}`,
              type: TransactionType.SALE,
              date: new Date().toISOString().split('T')[0],
              category: 'Product Sales',
              amount: total,
              description: `Payment for Invoice ${doc.number}`,
              reference: doc.number
          };
      }

      setState(prev => ({
          ...prev,
          documents: prev.documents.map(d => d.id === id ? { ...d, status } : d),
          transactions: newTransaction ? [newTransaction, ...prev.transactions] : prev.transactions
      }));

      await supabase.from('documents').update({ status }).eq('id', id);
      if (newTransaction) {
          await supabase.from('transactions').insert(newTransaction);
      }
  };

  const deleteDocument = async (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
    await supabase.from('documents').delete().eq('id', id);
  };

  const addTransaction = async (tx: Transaction) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
    await supabase.from('transactions').insert(tx);
  };

  const deleteTransaction = async (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
    await supabase.from('transactions').delete().eq('id', id);
  };

  const addCatalogItem = async (item: CatalogItem) => {
    setState(prev => ({ ...prev, catalog: [item, ...prev.catalog] }));
    await supabase.from('catalog_items').insert(item);
  };

  const updateCatalogItem = async (item: CatalogItem) => {
    setState(prev => ({
      ...prev,
      catalog: prev.catalog.map(i => i.id === item.id ? item : i)
    }));
    await supabase.from('catalog_items').update(item).eq('id', item.id);
  };

  const deleteCatalogItem = async (id: string) => {
    setState(prev => ({ ...prev, catalog: prev.catalog.filter(i => i.id !== id) }));
    await supabase.from('catalog_items').delete().eq('id', id);
  };

  const addClient = async (client: Client) => {
    setState(prev => ({ ...prev, clients: [client, ...prev.clients] }));
    await supabase.from('clients').insert(client);
  };

  const addClients = async (newClients: Client[]) => {
    setState(prev => ({ ...prev, clients: [...newClients, ...prev.clients] }));
    await supabase.from('clients').insert(newClients);
  };

  const updateClient = async (client: Client) => {
    setState(prev => ({
      ...prev,
      clients: prev.clients.map(c => c.id === client.id ? client : c)
    }));
    await supabase.from('clients').update(client).eq('id', client.id);
  };

  const deleteClient = async (id: string) => {
    setState(prev => ({ ...prev, clients: prev.clients.filter(c => c.id !== id) }));
    await supabase.from('clients').delete().eq('id', id);
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-50">
        <div className="bg-blue-600 p-3 rounded-2xl text-white animate-bounce mb-4">
          <i className="fa-solid fa-bolt text-3xl"></i>
        </div>
        <p className="text-slate-500 font-medium animate-pulse">Syncing with Supabase...</p>
      </div>
    );
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden relative">
        <Sidebar isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} />

        <div className="flex-1 flex flex-col min-w-0">
          <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-1.5 rounded-lg text-white">
                <i className="fa-solid fa-bolt text-xs"></i>
              </div>
              <h1 className="font-bold text-slate-900 tracking-tight">Invoice ME</h1>
            </div>
            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
            >
              <i className="fa-solid fa-bars text-xl"></i>
            </button>
          </header>

          <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <Routes>
              <Route path="/" element={<Dashboard state={state} />} />
              <Route 
                path="/quotations" 
                element={<DocumentManager 
                  type={DocumentType.QUOTATION} 
                  state={state} 
                  addDocument={addDocument}
                  updateDocument={updateDocument}
                  deleteDocument={deleteDocument}
                  updateStatus={updateDocumentStatus}
                  addClient={addClient}
                />} 
              />
              <Route 
                path="/invoices" 
                element={<DocumentManager 
                  type={DocumentType.INVOICE} 
                  state={state} 
                  addDocument={addDocument}
                  updateDocument={updateDocument}
                  deleteDocument={deleteDocument}
                  updateStatus={updateDocumentStatus}
                  addClient={addClient}
                />} 
              />
              <Route 
                path="/clients" 
                element={<ClientManager 
                  state={state} 
                  addClient={addClient}
                  addClients={addClients}
                  updateClient={updateClient}
                  deleteClient={deleteClient}
                />} 
              />
              <Route 
                path="/catalog" 
                element={<CatalogManager 
                  state={state} 
                  addItem={addCatalogItem}
                  updateItem={updateCatalogItem}
                  deleteItem={deleteCatalogItem}
                />} 
              />
              <Route 
                path="/sales" 
                element={<TransactionManager 
                  type={TransactionType.SALE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction}
                />} 
              />
              <Route 
                path="/expenses" 
                element={<TransactionManager 
                  type={TransactionType.EXPENSE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction}
                />} 
              />
              <Route 
                path="/settings" 
                element={<Settings business={state.business} updateBusiness={updateBusiness} />} 
              />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Document, BusinessDetails } from '../types';

export const generatePDF = (doc: Document, business: BusinessDetails, viewMode: boolean = false) => {
  const pdf = new jsPDF();
  const margin = 20;
  const pageWidth = pdf.internal.pageSize.width;
  const pageHeight = pdf.internal.pageSize.height;

  // Color Palette
  const accentColor: [number, number, number] = [37, 99, 235]; // blue-600
  const lightBlue: [number, number, number] = [147, 197, 253]; // blue-300
  const secondaryColor: [number, number, number] = [15, 23, 42]; // Slate-900
  const lightGray: [number, number, number] = [100, 116, 139]; // Slate-500

  const formatDateDisplay = (dateStr: string) => {
    if (!dateStr) return '';
    return dateStr.split('-').reverse().join('-');
  };

  // 1. Top Decorative Bar
  pdf.setFillColor(...accentColor);
  pdf.rect(0, 0, pageWidth, 2, 'F');

  let currentY = margin;

  // 2. Logo (Top Left)
  if (business.logoUrl) {
    try {
      const imgProps = pdf.getImageProperties(business.logoUrl);
      const maxWidth = 45;
      const maxHeight = 20;

      const widthRatio = maxWidth / imgProps.width;
      const heightRatio = maxHeight / imgProps.height;
      const ratio = Math.min(widthRatio, heightRatio);

      const finalWidth = imgProps.width * ratio;
      const finalHeight = imgProps.height * ratio;

      pdf.addImage(business.logoUrl, 'PNG', margin, currentY, finalWidth, finalHeight, undefined, 'FAST');
      currentY += finalHeight + 5; 
    } catch (e) {
      console.error("Failed to add logo to PDF", e);
      currentY += 10;
    }
  } else {
    currentY += 10;
  }

  // 3. Header Section - Metadata (Right)
  const rightAlignX = pageWidth - margin;
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(28);
  pdf.setTextColor(...accentColor);
  const metaY = Math.max(margin, currentY - 20); 
  pdf.text(doc.type.toUpperCase(), rightAlignX, metaY + 5, { align: 'right' });

  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text(`NO: ${doc.number}`, rightAlignX, metaY + 12, { align: 'right' });

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(`Issue Date: ${formatDateDisplay(doc.date)}`, rightAlignX, metaY + 18, { align: 'right' });
  pdf.text(`Due Date: ${formatDateDisplay(doc.dueDate)}`, rightAlignX, metaY + 23, { align: 'right' });

  // 4. Header Section - Business Info (Left)
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(18);
  pdf.setTextColor(...secondaryColor);
  pdf.text(business.name.toUpperCase(), margin, currentY + 5);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);

  const addressLines = pdf.splitTextToSize(business.address, 75);
  pdf.text(addressLines, margin, currentY + 12);

  const addressHeight = addressLines.length * 5;
  const contactY = currentY + 12 + addressHeight;

  pdf.text(`Email: ${business.email}`, margin, contactY);
  pdf.text(`Phone: ${business.phone}`, margin, contactY + 5);
  pdf.setFont('helvetica', 'bold');
  pdf.setTextColor(...secondaryColor);
  pdf.text(`TIN Number: ${business.tinNumber}`, margin, contactY + 10);

  const headerEndRight = metaY + 23;
  const headerEndLeft = contactY + 10;
  currentY = Math.max(headerEndRight, headerEndLeft) + 10;

  pdf.setDrawColor(241, 245, 249); 
  pdf.line(margin, currentY, pageWidth - margin, currentY);

  // 6. Bill To Section
  currentY += 10;
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('BILL TO', margin, currentY);

  pdf.setFontSize(12);
  pdf.text(doc.clientName, margin, currentY + 7);

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);
  pdf.text(doc.clientEmail, margin, currentY + 13);

  // 7. Main Table
  const tableHeaders = [['DESCRIPTION', 'QTY', 'UNIT PRICE', 'TOTAL']];
  const tableData = doc.items.map(item => [
    item.description,
    item.quantity.toString(),
    `${business.currency} ${item.unitPrice.toLocaleString(undefined, { minimumFractionDigits: 2 })}`,
    `${business.currency} ${(item.quantity * item.unitPrice).toLocaleString(undefined, { minimumFractionDigits: 2 })}`
  ]);

  const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  const taxAmount = (subtotal * business.taxPercentage) / 100;
  const total = subtotal + taxAmount;

  autoTable(pdf, {
    startY: currentY + 25,
    head: tableHeaders,
    body: tableData,
    theme: 'plain',
    headStyles: { 
      fillColor: [248, 250, 252],
      textColor: secondaryColor,
      fontStyle: 'bold',
      fontSize: 9,
      cellPadding: 4,
    },
    bodyStyles: { 
      fontSize: 9,
      textColor: secondaryColor,
      cellPadding: 4
    },
    columnStyles: {
      0: { halign: 'left' },
      1: { halign: 'center', cellWidth: 20 },
      2: { halign: 'right', cellWidth: 45 },
      3: { halign: 'right', fontStyle: 'bold', cellWidth: 45 }
    },
    margin: { left: margin, right: margin },
    didParseCell: (data) => {
      if (data.section === 'head') {
        const colIndex = data.column.index;
        if (colIndex === 1) data.cell.styles.halign = 'center';
        if (colIndex === 2 || colIndex === 3) data.cell.styles.halign = 'right';
      }
    },
    didDrawCell: (data) => {
        if (data.section === 'body') {
            pdf.setDrawColor(241, 245, 249);
            pdf.line(data.cell.x, data.cell.y + data.cell.height, data.cell.x + data.cell.width, data.cell.y + data.cell.height);
        }
    }
  });

  // 8. Summary Block
  const summaryY = ((pdf as any).lastAutoTable?.finalY || 150) + 15;
  const summaryX = pageWidth - margin;
  const labelX = pageWidth - margin - 90; 

  // Watermark drawn BEFORE text to be "behind"
  if (doc.status === 'Paid') {
    pdf.saveGraphicsState();
    const GState = (pdf as any).GState;
    if (GState) {
        pdf.setGState(new GState({ opacity: 0.12 })); 
    }
    pdf.setFontSize(65);
    pdf.setFont('helvetica', 'bold');
    pdf.setTextColor(16, 185, 129); 

    pdf.text('PAID', pageWidth * 0.7, summaryY + 15, { 
      angle: 12, 
      align: 'center'
    });
    pdf.restoreGraphicsState();
  }

  // Draw Summary Text
  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...lightGray);

  pdf.text('Subtotal:', labelX, summaryY);
  pdf.text(`${business.currency} ${subtotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, summaryY, { align: 'right' });

  pdf.text(`Tax (${business.taxPercentage}%):`, labelX, summaryY + 8);
  pdf.text(`${business.currency} ${taxAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, summaryY + 8, { align: 'right' });

  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(10);
  pdf.setTextColor(...secondaryColor);
  pdf.text('TOTAL AMOUNT:', labelX, summaryY + 22);

  pdf.setFontSize(16);
  pdf.setTextColor(...accentColor);
  pdf.text(`${business.currency} ${total.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, summaryX, summaryY + 22, { align: 'right' });

  let footerContentY = summaryY + 45;

  if (doc.notes) {
    pdf.setFont('helvetica', 'bold');
    pdf.setFontSize(9);
    pdf.setTextColor(...secondaryColor);
    pdf.text('NOTES & TERMS', margin, footerContentY);

    pdf.setFont('helvetica', 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(...lightGray);
    const splitNotes = pdf.splitTextToSize(doc.notes, pageWidth - (2 * margin));
    pdf.text(splitNotes, margin, footerContentY + 5);
    footerContentY += (splitNotes.length * 4) + 12;
  }

  if (business.paymentDetails) {
    pdf.setFont('helvetica', 'bold');
    pdf.setFontSize(9);
    pdf.setTextColor(...secondaryColor);
    pdf.text('PAYMENT DETAILS', margin, footerContentY);

    pdf.setFont('helvetica', 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(...lightGray);
    const splitPayment = pdf.splitTextToSize(business.paymentDetails, pageWidth - (2 * margin));
    pdf.text(splitPayment, margin, footerContentY + 5);
  }

  // 9. Modern Geometric Footer Pattern
  const footerHeight = 20;
  const patternOpacity = 0.3;

  pdf.saveGraphicsState();
  const GState = (pdf as any).GState;
  if (GState) {
      pdf.setGState(new GState({ opacity: patternOpacity }));
  }

  pdf.setFillColor(...lightBlue);
  pdf.rect(0, pageHeight - footerHeight, pageWidth, footerHeight, 'F');

  pdf.setFillColor(...accentColor);
  pdf.rect(0, pageHeight - footerHeight, pageWidth * 0.20, footerHeight, 'F');
  pdf.triangle(
      pageWidth * 0.20, pageHeight - footerHeight,
      pageWidth * 0.25, pageHeight,
      pageWidth * 0.20, pageHeight,
      'F'
  );

  pdf.setFillColor(...secondaryColor);
  pdf.triangle(
      pageWidth, pageHeight,
      pageWidth * 0.70, pageHeight,
      pageWidth, pageHeight - footerHeight,
      'F'
  );

  pdf.setDrawColor(...accentColor);
  pdf.setLineWidth(0.5);
  pdf.line(0, pageHeight - footerHeight, pageWidth, pageHeight - footerHeight);

  pdf.restoreGraphicsState();

  // Footer Text
  pdf.setFont('helvetica', 'bold');
  pdf.setFontSize(7);
  pdf.setTextColor(...secondaryColor);
  pdf.text(`${business.name.toUpperCase()}  |  TIN: ${business.tinNumber}`, pageWidth / 2, pageHeight - 6, { align: 'center' });

  pdf.setFont('helvetica', 'normal');
  pdf.setFontSize(7);
  pdf.setTextColor(...lightGray);
  pdf.text(`This is a computer generated document.`, pageWidth / 2, pageHeight - 12, { align: 'center' });

  if (viewMode) {
    const blobURL = pdf.output('bloburl');
    window.open(blobURL as any, '_blank');
  } else {
    pdf.save(`${doc.type}_${doc.number}.pdf`);
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import CatalogManager from './components/CatalogManager';
import ClientManager from './components/ClientManager';
import Settings from './components/Settings';
import { AppState, DocumentType, TransactionType, Document, Transaction, CatalogItem, Client, BusinessDetails } from './types';
import { supabase } from './lib/supabase';

const INITIAL_STATE: AppState = {
  business: {
    name: 'SANDPIX MALDIVES',
    email: 'info@sandpixmaldives.com',
    phone: '+960 797 3617',
    address: 'Blue House, HDh. Nellaidhoo, Maldives',
    tinNumber: '1106645GST501',
    currency: 'MVR',
    taxPercentage: 8,
    invoicePrefix: 'INV',
    quotationPrefix: 'QT',
    defaultTerms: '1. Please pay within 7 days.\n2. Goods once sold are not returnable.',
    paymentDetails: 'Bank: Bank of Maldives (BML)\nAccount Name: SANDPIX MALDIVES\nAccount Number: 7730000000001\nBranch: Main Branch'
  },
  documents: [],
  transactions: [],
  catalog: [],
  clients: []
};

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [state, setState] = useState<AppState>(INITIAL_STATE);

  // Initial Data Fetch from Supabase
  useEffect(() => {
    const fetchAllData = async () => {
      setIsLoading(true);
      try {
        const [
          { data: businessData, error: bizError },
          { data: docsData },
          { data: txsData },
          { data: catalogData },
          { data: clientsData }
        ] = await Promise.all([
          supabase.from('business_settings').select('*').eq('id', 1).maybeSingle(),
          supabase.from('documents').select('*').order('created_at', { ascending: false }),
          supabase.from('transactions').select('*').order('created_at', { ascending: false }),
          supabase.from('catalog_items').select('*').order('created_at', { ascending: false }),
          supabase.from('clients').select('*').order('created_at', { ascending: false })
        ]);

        // If no business data found (first time), try to insert initial data
        let activeBusiness = businessData || INITIAL_STATE.business;
        if (!businessData && !bizError) {
           const { data: inserted } = await supabase.from('business_settings').insert({ id: 1, ...INITIAL_STATE.business }).select().single();
           if (inserted) activeBusiness = inserted;
        }

        setState({
          business: activeBusiness,
          documents: docsData || [],
          transactions: txsData || [],
          catalog: catalogData || [],
          clients: clientsData || []
        });
      } catch (err) {
        console.error("Failed to fetch data from Supabase:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchAllData();
  }, []);

  const updateBusiness = async (business: BusinessDetails) => {
    // 1. Update UI state immediately for responsiveness
    setState(prev => ({ ...prev, business }));

    // 2. Persist to Supabase using id:1 to ensure only one profile exists
    const { error } = await supabase
      .from('business_settings')
      .upsert({ id: 1, ...business });

    if (error) {
      console.error("Error updating business settings:", error);
      alert(`Sync Error: ${error.message}. Ensure your database schema matches.`);
    }
  };

  const addDocument = async (doc: Document) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
    await supabase.from('documents').insert(doc);
  };

  const updateDocument = async (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => d.id === doc.id ? doc : d)
    }));
    await supabase.from('documents').update(doc).eq('id', doc.id);
  };

  const updateDocumentStatus = async (id: string, status: 'Draft' | 'Sent' | 'Paid' | 'Expired') => {
      const doc = state.documents.find(d => d.id === id);
      if (!doc) return;

      let newTransaction: Transaction | null = null;
      if (doc.type === DocumentType.INVOICE && status === 'Paid' && doc.status !== 'Paid') {
          const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
          const taxAmount = (subtotal * state.business.taxPercentage) / 100;
          const total = subtotal + taxAmount;

          newTransaction = {
              id: `sale-inv-${doc.id}-${Date.now()}`,
              type: TransactionType.SALE,
              date: new Date().toISOString().split('T')[0],
              category: 'Product Sales',
              amount: total,
              description: `Payment for Invoice ${doc.number}`,
              reference: doc.number
          };
      }

      setState(prev => ({
          ...prev,
          documents: prev.documents.map(d => d.id === id ? { ...d, status } : d),
          transactions: newTransaction ? [newTransaction, ...prev.transactions] : prev.transactions
      }));

      await supabase.from('documents').update({ status }).eq('id', id);
      if (newTransaction) {
          await supabase.from('transactions').insert(newTransaction);
      }
  };

  const deleteDocument = async (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
    await supabase.from('documents').delete().eq('id', id);
  };

  const addTransaction = async (tx: Transaction) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
    await supabase.from('transactions').insert(tx);
  };

  const deleteTransaction = async (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
    await supabase.from('transactions').delete().eq('id', id);
  };

  const addCatalogItem = async (item: CatalogItem) => {
    setState(prev => ({ ...prev, catalog: [item, ...prev.catalog] }));
    await supabase.from('catalog_items').insert(item);
  };

  const updateCatalogItem = async (item: CatalogItem) => {
    setState(prev => ({
      ...prev,
      catalog: prev.catalog.map(i => i.id === item.id ? item : i)
    }));
    await supabase.from('catalog_items').update(item).eq('id', item.id);
  };

