export enum DocumentType {
  QUOTATION = 'QUOTATION',
  INVOICE = 'INVOICE'
}

export enum TransactionType {
  SALE = 'SALE',
  EXPENSE = 'EXPENSE'
}

export interface BusinessDetails {
  name: string;
  email: string;
  phone: string;
  address: string;
  tinNumber: string;
  currency: string;
  taxPercentage: number;
  invoicePrefix: string;
  quotationPrefix: string;
  logoUrl?: string;
  defaultTerms?: string;
  paymentDetails?: string;
  poweredByText?: string;
}

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface CatalogItem {
  id: string;
  description: string;
  unitPrice: number;
}

export interface Client {
  id: string;
  name: string;
  email: string;
  phone: string;
  address: string;
}

