import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import CatalogManager from './components/CatalogManager';
import ClientManager from './components/ClientManager';
import Settings from './components/Settings';
import { AppState, DocumentType, TransactionType, Document, Transaction, CatalogItem, Client, BusinessDetails } from './types';
import { supabase } from './lib/supabase';

const INITIAL_STATE: AppState = {
  business: {
    name: 'SANDPIX MALDIVES',
    email: 'info@sandpixmaldives.com',
    phone: '+960 797 3617',
    address: 'Blue House, HDh. Nellaidhoo, Maldives',
    tinNumber: '1106645GST501',
    currency: 'MVR',
    taxPercentage: 8,
    invoicePrefix: 'INV',
    quotationPrefix: 'QT',
    defaultTerms: '1. Please pay within 7 days.\n2. Goods once sold are not returnable.',
    paymentDetails: 'Bank: Bank of Maldives (BML)\nAccount Name: SANDPIX MALDIVES\nAccount Number: 7730000000001\nBranch: Main Branch',
    poweredByText: 'SANDPIX MALDIVES'
  },
  documents: [],
  transactions: [],
  catalog: [],
  clients: []
};

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [state, setState] = useState<AppState>(INITIAL_STATE);

  // Initial Data Fetch from Supabase
  useEffect(() => {
    const fetchAllData = async () => {
      setIsLoading(true);
      try {
        const [
          { data: businessData, error: bizError },
          { data: docsData },
          { data: txsData },
          { data: catalogData },
          { data: clientsData }
        ] = await Promise.all([
          supabase.from('business_settings').select('*').eq('id', 1).maybeSingle(),
          supabase.from('documents').select('*').order('created_at', { ascending: false }),
          supabase.from('transactions').select('*').order('created_at', { ascending: false }),
          supabase.from('catalog_items').select('*').order('created_at', { ascending: false }),
          supabase.from('clients').select('*').order('created_at', { ascending: false })
        ]);

        let activeBusiness = businessData ? { ...INITIAL_STATE.business, ...businessData } : INITIAL_STATE.business;

        if (!businessData && !bizError) {
           const { data: inserted } = await supabase.from('business_settings').insert({ id: 1, ...INITIAL_STATE.business }).select().single();
           if (inserted) activeBusiness = { ...INITIAL_STATE.business, ...inserted };
        }

        setState({
          business: activeBusiness,
          documents: docsData || [],
          transactions: txsData || [],
          catalog: catalogData || [],
          clients: clientsData || []
        });
      } catch (err) {
        console.error("Failed to fetch data from Supabase:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchAllData();
  }, []);

  const updateBusiness = async (business: BusinessDetails) => {
    // Immediate UI Update
    setState(prev => ({ ...prev, business }));

    // Defensive Persist
    try {
        const { error } = await supabase
            .from('business_settings')
            .upsert({ id: 1, ...business });

        if (error) {
            // Silently handle schema cache errors (PGRST204)
            console.warn("Supabase Sync Warning:", error.message);
        }
    } catch (err) {
        console.error("Critical Sync Error:", err);
    }
  };

  const addDocument = async (doc: Document) => {
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
    await supabase.from('documents').insert(doc);
  };

  const updateDocument = async (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => d.id === doc.id ? doc : d)
    }));
    await supabase.from('documents').update(doc).eq('id', doc.id);
  };

  const updateDocumentStatus = async (id: string, status: 'Draft' | 'Sent' | 'Paid' | 'Expired') => {
      const doc = state.documents.find(d => d.id === id);
      if (!doc) return;

      let newTransaction: Transaction | null = null;
      if (doc.type === DocumentType.INVOICE && status === 'Paid' && doc.status !== 'Paid') {
          const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
          const taxAmount = (subtotal * state.business.taxPercentage) / 100;
          const total = subtotal + taxAmount;

          newTransaction = {
              id: `sale-inv-${doc.id}-${Date.now()}`,
              type: TransactionType.SALE,
              date: new Date().toISOString().split('T')[0],
              category: 'Product Sales',
              amount: total,
              description: `Payment for Invoice ${doc.number}`,
              reference: doc.number
          };
      }

      setState(prev => ({
          ...prev,
          documents: prev.documents.map(d => d.id === id ? { ...d, status } : d),
          transactions: newTransaction ? [newTransaction, ...prev.transactions] : prev.transactions
      }));

      await supabase.from('documents').update({ status }).eq('id', id);
      if (newTransaction) {
          await supabase.from('transactions').insert(newTransaction);
      }
  };

  const deleteDocument = async (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => d.id !== id) }));
    await supabase.from('documents').delete().eq('id', id);
  };

  const addTransaction = async (tx: Transaction) => {
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
    await supabase.from('transactions').insert(tx);
  };

  const deleteTransaction = async (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => t.id !== id) }));
    await supabase.from('transactions').delete().eq('id', id);
  };

  const addCatalogItem = async (item: CatalogItem) => {
    setState(prev => ({ ...prev, catalog: [item, ...prev.catalog] }));
    await supabase.from('catalog_items').insert(item);
  };

  const updateCatalogItem = async (item: CatalogItem) => {
    setState(prev => ({
      ...prev,
      catalog: prev.catalog.map(i => i.id === item.id ? item : i)
    }));
    await supabase.from('catalog_items').update(item).eq('id', item.id);
  };

  const deleteCatalogItem = async (id: string) => {
    setState(prev => ({ ...prev, catalog: prev.catalog.filter(i => i.id !== id) }));
    await supabase.from('catalog_items').delete().eq('id', id);
  };

  const addClient = async (client: Client) => {
    setState(prev => ({ ...prev, clients: [client, ...prev.clients] }));
    await supabase.from('clients').insert(client);
  };

  const addClients = async (newClients: Client[]) => {
    setState(prev => ({ ...prev, clients: [...newClients, ...prev.clients] }));
    await supabase.from('clients').insert(newClients);
  };

  const updateClient = async (client: Client) => {
    setState(prev => ({
      ...prev,
      clients: prev.clients.map(c => c.id === client.id ? client : c)
    }));
    await supabase.from('clients').update(client).eq('id', client.id);
  };

  const deleteClient = async (id: string) => {
    setState(prev => ({ ...prev, clients: prev.clients.filter(c => c.id !== id) }));
    await supabase.from('clients').delete().eq('id', id);
  };

  if (isLoading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-50">
        <div className="bg-blue-600 p-3 rounded-2xl text-white animate-bounce mb-4">
          <i className="fa-solid fa-bolt text-3xl"></i>
        </div>
        <p className="text-slate-500 font-medium animate-pulse">Syncing Business Ledger...</p>
      </div>
    );
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 overflow-hidden relative">
        <Sidebar isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} business={state.business} />

        <div className="flex-1 flex flex-col min-w-0">
          <header className="md:hidden bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between sticky top-0 z-30">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-1.5 rounded-lg text-white">
                <i className="fa-solid fa-bolt text-xs"></i>
              </div>
              <h1 className="font-bold text-slate-900 tracking-tight">Invoice ME</h1>
            </div>
            <button 
              onClick={() => setIsSidebarOpen(true)}
              className="p-2 text-slate-600 hover:bg-slate-100 rounded-lg transition-colors"
            >
              <i className="fa-solid fa-bars text-xl"></i>
            </button>
          </header>

          <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <Routes>
              <Route path="/" element={<Dashboard state={state} />} />
              <Route 
                path="/quotations" 
                element={<DocumentManager 
                  type={DocumentType.QUOTATION} 
                  state={state} 
                  addDocument={addDocument}
                  updateDocument={updateDocument}
                  deleteDocument={deleteDocument}
                  updateStatus={updateDocumentStatus}
                  addClient={addClient}
                />} 
              />
              <Route 
                path="/invoices" 
                element={<DocumentManager 
                  type={DocumentType.INVOICE} 
                  state={state} 
                  addDocument={addDocument}
                  updateDocument={updateDocument}
                  deleteDocument={deleteDocument}
                  updateStatus={updateDocumentStatus}
                  addClient={addClient}
                />} 
              />
              <Route 
                path="/clients" 
                element={<ClientManager 
                  state={state} 
                  addClient={addClient}
                  addClients={addClients}
                  updateClient={updateClient}
                  deleteClient={deleteClient}
                />} 
              />
              <Route 
                path="/catalog" 
                element={<CatalogManager 
                  state={state} 
                  addItem={addCatalogItem}
                  updateItem={updateCatalogItem}
                  deleteItem={deleteCatalogItem}
                />} 
              />
              <Route 
                path="/sales" 
                element={<TransactionManager 
                  type={TransactionType.SALE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction}
                />} 
              />
              <Route 
                path="/expenses" 
                element={<TransactionManager 
                  type={TransactionType.EXPENSE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction}
                />} 
              />
              <Route 
                path="/settings" 
                element={<Settings business={state.business} updateBusiness={updateBusiness} />} 
              />
              <Route path="*" element={<Navigate to="/" replace />} />
            </Routes>
          </main>
        </div>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { BusinessDetails } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  business: BusinessDetails;
  updateBusiness: (details: BusinessDetails) => void;
}

const CURRENCIES = [
    { code: 'MVR', symbol: 'Rf', name: 'Maldivian Rufiyaa' },
    { code: 'USD', symbol: '$', name: 'US Dollar' },
    { code: 'EUR', symbol: '€', name: 'Euro' },
    { code: 'GBP', symbol: '£', name: 'British Pound' },
    { code: 'INR', symbol: '₹', name: 'Indian Rupee' },
    { code: 'AED', symbol: 'DH', name: 'UAE Dirham' }
];

const Settings: React.FC<Props> = ({ business, updateBusiness }) => {
  const [details, setDetails] = useState<BusinessDetails>(business);
  const [isSaved, setIsSaved] = useState(false);
  const [isGeneratingTerms, setIsGeneratingTerms] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateBusiness(details);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleLogoClick = () => {
    fileInputRef.current?.click();
  };

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setDetails(prev => ({ ...prev, logoUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLogo = (e: React.MouseEvent) => {
    e.stopPropagation();
    setDetails(prev => ({ ...prev, logoUrl: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleGenerateTerms = async () => {
    setIsGeneratingTerms(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Generate a modern, professional, and concise set of "Terms and Conditions" for a business named "${details.name || 'our company'}". 
      The terms should be formatted as a numbered list and include:
      1. Payment deadlines.
      2. Quote validity period.
      3. Brief note on cancellations or returns.
      4. Late payment interest note.
      Keep it under 150 words and sounding very professional.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });

      const generatedText = response.text;
      if (generatedText) {
        setDetails(prev => ({ ...prev, defaultTerms: generatedText.trim() }));
      }
    } catch (error) {
      console.error("Failed to generate terms:", error);
    } finally {
      setIsGeneratingTerms(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 md:space-y-8 animate-fadeIn pb-12">
      <header>
        <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Settings</h1>
        <p className="text-sm text-slate-500">Configure your company identity and regional preferences.</p>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 md:p-8 border-b border-slate-100 bg-slate-50/50">
            <div className="flex flex-col sm:flex-row items-center gap-6">
                <div 
                  onClick={handleLogoClick}
                  className="group relative w-24 h-24 rounded-2xl bg-slate-200 flex items-center justify-center border-4 border-white shadow-sm overflow-hidden cursor-pointer hover:bg-slate-300 transition-all shrink-0"
                >
                    {details.logoUrl ? (
                      <img src={details.logoUrl} className="w-full h-full object-cover" alt="Business Logo" />
                    ) : (
                      <i className="fa-solid fa-building text-4xl text-slate-400"></i>
                    )}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <i className="fa-solid fa-camera text-white text-xl"></i>
                    </div>
                </div>

                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*"
                  onChange={handleLogoChange}
                />

                <div className="text-center sm:text-left">
                    <h2 className="text-xl font-bold text-slate-800 truncate max-w-[250px] md:max-w-md">{details.name || 'Your Company Name'}</h2>
                    <p className="text-slate-500 text-sm">Update your logo and business information</p>
                    <div className="flex justify-center sm:justify-start gap-4 mt-3">
                      <button 
                        type="button" 
                        onClick={handleLogoClick}
                        className="text-blue-600 text-xs font-semibold hover:underline flex items-center gap-1"
                      >
                        <i className="fa-solid fa-upload"></i>
                        Change Logo
                      </button>
                      {details.logoUrl && (
                        <button 
                          type="button" 
                          onClick={removeLogo}
                          className="text-red-500 text-xs font-semibold hover:underline flex items-center gap-1"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                          Remove
                        </button>
                      )}
                    </div>
                </div>
            </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-10">
          <section className="space-y-6">
            <h3 className="text-base md:text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Business Identity</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 md:gap-6">
                <div className="col-span-1 md:col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Company Name</label>
                <input 
                    required
                    value={details.name}
                    onChange={(e) => setDetails({...details, name: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Business Email</label>
                <input 
                    required
                    type="email"
                    value={details.email}
                    onChange={(e) => setDetails({...details, email: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Phone Number</label>
                <input 
                    required
                    value={details.phone}
                    onChange={(e) => setDetails({...details, phone: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div className="col-span-1 md:col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Physical Address</label>
                <input 
                    required
                    value={details.address}
                    onChange={(e) => setDetails({...details, address: e.target.value})}
