                <div className={`w-5 flex justify-center transition-transform group-hover:scale-110 ${isActive ? 'text-white' : 'text-slate-600 group-hover:text-blue-400'}`}>
                  <i className={`fa-solid ${item.icon} text-lg`}></i>
