import React, { useState } from 'react';
import { AppState, User, UserRole } from '../types';

interface Props {
  state: AppState;
  addUser: (user: User) => Promise<boolean | undefined>;
  updateUser: (user: User) => Promise<boolean | undefined>;
  deleteUser: (id: string) => void;
}

const UserManager: React.FC<Props> = ({ state, addUser, updateUser, deleteUser }) => {
  const [showModal, setShowModal] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    username: '',
    password: '',
    role: 'user' as UserRole
  });

  const resetForm = () => {
    setFormData({ name: '', username: '', password: '', role: 'user' });
    setEditingId(null);
    setShowModal(false);
    setErrorMsg(null);
    setIsSubmitting(false);
  };

  const handleEdit = (user: User) => {
    setFormData({
      name: user.name,
      username: user.username,
      password: user.password || '',
      role: user.role
    });
    setEditingId(user.id);
    setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);
    setIsSubmitting(true);

    try {
        // Duplicate Username Check (excluding current user if editing)
        const isDuplicate = state.users.some(u => 
          String(u.id) !== String(editingId) && 
          u.username.toLowerCase() === formData.username.toLowerCase()
        );

        if (isDuplicate) {
          setErrorMsg("This username is already taken. Please choose a unique identity.");
          setIsSubmitting(false);
          return;
        }

        if (editingId) {
          const success = await updateUser({
            id: editingId,
            ...formData
          });
          if (success) resetForm();
        } else {
          const success = await addUser({
            id: `temp-${Date.now()}`,
            ...formData
          });
          if (success) resetForm();
        }
    } catch (err: any) {
        setErrorMsg(err.message || "Failed to establish user record. Verify system connectivity.");
    } finally {
        setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <div className="p-2 rounded-xl text-white bg-blue-600">
              <i className="fa-solid fa-user-gear text-lg"></i>
            </div>
            <h1 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tight">System Access</h1>
          </div>
          <p className="text-slate-500 font-medium">Manage user accounts and system permissions.</p>
        </div>

        <button 
          onClick={() => { resetForm(); setShowModal(true); }}
          className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-bold hover:bg-black transition-all flex items-center justify-center gap-2 text-sm shadow-xl shadow-slate-200"
        >
          <i className="fa-solid fa-plus"></i>
          Provision User
        </button>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50">
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identitiy</th>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Username</th>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Role</th>
                <th className="px-10 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {state.users.length === 0 ? (
                <tr>
                   <td colSpan={4} className="px-10 py-12 text-center text-slate-400 font-medium italic">No active users recorded.</td>
                </tr>
              ) : state.users.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-10 py-6">
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-xl bg-slate-100 flex items-center justify-center font-black text-slate-500">
                        {u.name.charAt(0)}
                      </div>
                      <span className="font-bold text-slate-900">{u.name}</span>
                    </div>
                  </td>
                  <td className="px-10 py-6 text-sm font-medium text-slate-600">{u.username}</td>
                  <td className="px-10 py-6">
                    <span className={`text-[9px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full border ${
                      u.role === 'admin' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-slate-100 text-slate-600 border-slate-200'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-10 py-6 text-right">
                    <div className="flex justify-end gap-2">
                      <button 
                        onClick={() => handleEdit(u)}
                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-xl transition-colors"
                        title="Edit User"
                      >
                        <i className="fa-solid fa-pen-to-square"></i>
                      </button>
                      <button 
                        disabled={u.username === 'Ihsaan'}
                        onClick={() => { if(window.confirm(`Delete user ${u.name}?`)) deleteUser(u.id); }}
                        className="p-2 text-rose-500 hover:bg-rose-50 rounded-xl transition-colors disabled:opacity-30"
                        title="Delete User"
                      >
                        <i className="fa-solid fa-trash-can"></i>
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg shadow-2xl overflow-hidden animate-slideUp">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center">
              <h2 className="text-xl font-black text-slate-900">
                {editingId ? 'Modify Account' : 'Provision Account'}
              </h2>
              <button disabled={isSubmitting} onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600 disabled:opacity-50">
                <i className="fa-solid fa-xmark text-2xl"></i>
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-8 space-y-5">
              {errorMsg && (
                <div className="bg-rose-50 border border-rose-100 text-rose-600 px-4 py-3 rounded-2xl text-xs font-bold flex items-center gap-2 animate-fadeIn">
                  <i className="fa-solid fa-circle-exclamation text-sm"></i>
                  {errorMsg}
                </div>
              )}
              <div className="space-y-2">
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Full Name</label>
                <input required disabled={isSubmitting} value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3.5 outline-none focus:ring-2 focus:ring-blue-600 font-bold disabled:opacity-50" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Username</label>
                  <input required disabled={isSubmitting} value={formData.username} onChange={(e) => setFormData({...formData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3.5 outline-none focus:ring-2 focus:ring-blue-600 font-bold disabled:opacity-50" />
                </div>
                <div className="space-y-2">
                  <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Password</label>
                  <input required disabled={isSubmitting} type="password" value={formData.password} onChange={(e) => setFormData({...formData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3.5 outline-none focus:ring-2 focus:ring-blue-600 font-bold disabled:opacity-50" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Access Role</label>
                <select 
                  disabled={isSubmitting || formData.username === 'Ihsaan'} 
                  value={formData.role} 
                  onChange={(e) => setFormData({...formData, role: e.target.value as UserRole})} 
                  className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3.5 outline-none focus:ring-2 focus:ring-blue-600 font-bold appearance-none disabled:opacity-50"
                >
                  <option value="user">Standard User</option>
                  <option value="admin">System Admin</option>
                </select>
                {formData.username === 'Ihsaan' && (
                  <p className="text-[9px] text-slate-400 italic mt-1 ml-1">Root administrator role is persistent.</p>
                )}
              </div>
              <div className="pt-6 flex justify-end gap-3">
                <button type="button" disabled={isSubmitting} onClick={() => resetForm()} className="px-8 py-4 border border-slate-200 rounded-2xl font-bold uppercase tracking-widest text-[10px] text-slate-500 disabled:opacity-50">Cancel</button>
                <button type="submit" disabled={isSubmitting} className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-blue-100 text-[10px] disabled:opacity-70 flex items-center gap-2">
                  {isSubmitting ? (
                      <>
                        <i className="fa-solid fa-spinner fa-spin"></i>
                        Processing...
                      </>
                  ) : (editingId ? 'Update Profile' : 'Create Account')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UserManager;

export enum DocumentType {
  QUOTATION = 'QUOTATION',
  INVOICE = 'INVOICE'
}

export enum TransactionType {
  SALE = 'SALE',
  EXPENSE = 'EXPENSE'
}

export type UserRole = 'admin' | 'user';

export interface User {
  id: string;
  username: string;
  password?: string;
  role: UserRole;
  name: string;
  isEnabled: boolean;
}

export interface BusinessDetails {
  name: string;
  email: string;
  phone: string;
  address: string;
  tinNumber: string;
  currency: string;
  taxPercentage: number;
  invoicePrefix: string;
  quotationPrefix: string;
  logoUrl?: string;
  defaultTerms?: string;
  paymentDetails?: string;
  poweredByText?: string;
}

export interface LineItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
}

export interface CatalogItem {
  id: string;
  description: string;
  unitPrice: number;
}

export interface Client {
  id: string;
  name: string;
  email?: string;
  phone: string;
  address: string;
}

export interface Document {
  id: string;
  type: DocumentType;
  number: string;
  date: string;
  dueDate: string;
  clientName: string;
  clientEmail?: string;
  items: LineItem[];
  status: 'Draft' | 'Sent' | 'Paid' | 'Expired';
  notes?: string;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  date: string;
  category: string;
  amount: number;
  description: string;
  reference?: string;
}

export interface AppState {
  business: BusinessDetails;
  documents: Document[];
  transactions: Transaction[];
  catalog: CatalogItem[];
  clients: Client[];
  users: User[];
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import DocumentManager from './components/DocumentManager';
import TransactionManager from './components/TransactionManager';
import CatalogManager from './components/CatalogManager';
import ClientManager from './components/ClientManager';
import Settings from './components/Settings';
import UserManager from './components/UserManager';
import Login from './components/Login';
import { AppState, DocumentType, TransactionType, Document, Transaction, CatalogItem, Client, BusinessDetails, User } from './types';
import { supabase } from './lib/supabase';

const INITIAL_STATE: AppState = {
  business: {
    name: 'SANDPIX MALDIVES',
    email: 'info@sandpixmaldives.com',
    phone: '+960 797 3617',
    address: 'Blue House, HDh. Nellaidhoo, Maldives',
    tinNumber: '1106645GST501',
    currency: 'MVR',
    taxPercentage: 8,
    invoicePrefix: 'INV',
    quotationPrefix: 'QT',
    defaultTerms: '1. Please pay within 7 days.\n2. Goods once sold are not returnable.',
    paymentDetails: 'Bank: Bank of Maldives (BML)\nAccount Name: SANDPIX MALDIVES\nAccount Number: 7730000000001\nBranch: Main Branch',
    poweredByText: 'SANDPIX MALDIVES'
  },
  documents: [],
  transactions: [],
  catalog: [],
  clients: [],
  users: []
};

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Initial Data Fetch from Supabase
  useEffect(() => {
    const fetchAllData = async () => {
      setIsLoading(true);
      try {
        const [
          { data: businessData, error: bizError },
          { data: docsData },
          { data: txsData },
          { data: catalogData },
          { data: clientsData },
          { data: usersData }
        ] = await Promise.all([
          supabase.from('business_settings').select('*').eq('id', 1).maybeSingle(),
          supabase.from('documents').select('*').order('created_at', { ascending: false }),
          supabase.from('transactions').select('*').order('created_at', { ascending: false }),
          supabase.from('catalog_items').select('*').order('created_at', { ascending: false }),
          supabase.from('clients').select('*').order('created_at', { ascending: false }),
          supabase.from('users').select('*').order('created_at', { ascending: false })
        ]);

        let activeBusiness = businessData ? { ...INITIAL_STATE.business, ...businessData } : INITIAL_STATE.business;

        if (!businessData && !bizError) {
           const { data: inserted } = await supabase.from('business_settings').insert({ id: 1, ...INITIAL_STATE.business }).select().single();
           if (inserted) activeBusiness = { ...INITIAL_STATE.business, ...inserted };
        }

        // Initialize default admin if no users exist
        let allUsers = (usersData || []) as User[];
        if (allUsers.length === 0) {
          const defaultAdmin = { username: 'Ihsaan', password: 'password123', role: 'admin' as const, name: 'Ihsaan', isEnabled: true };
          const { data: insertedUser } = await supabase.from('users').insert(defaultAdmin).select().single();
          if (insertedUser) allUsers = [insertedUser as User];
        }

        setState({
          business: activeBusiness,
          documents: (docsData || []).map(d => ({ ...d, id: String(d.id) })),
          transactions: (txsData || []).map(t => ({ ...t, id: String(t.id) })),
          catalog: (catalogData || []).map(i => ({ ...i, id: String(i.id) })),
          clients: (clientsData || []).map(c => ({ ...c, id: String(c.id) })),
          users: allUsers.map(u => ({ ...u, id: String(u.id), isEnabled: u.isEnabled ?? true }))
        });

        // Check session
        const savedUser = sessionStorage.getItem('ledger_user');
        if (savedUser) {
          setCurrentUser(JSON.parse(savedUser));
        }

      } catch (err) {
        console.error("Failed to fetch data from Supabase:", err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchAllData();
  }, []);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    sessionStorage.setItem('ledger_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    sessionStorage.removeItem('ledger_user');
  };

  const updateBusiness = async (business: BusinessDetails) => {
    setState(prev => ({ ...prev, business }));
    try {
        await supabase.from('business_settings').upsert({ id: 1, ...business });
    } catch (err) {
        console.error("Critical Sync Error:", err);
    }
  };

  const addDocument = async (doc: Document) => {
    const tempId = doc.id;
    setState(prev => ({ ...prev, documents: [doc, ...prev.documents] }));
    try {
        const { id, ...docData } = doc;
        const { data } = await supabase.from('documents').insert(docData).select().single();
        if (data) {
            setState(prev => ({
                ...prev,
                documents: prev.documents.map(d => String(d.id) === String(tempId) ? { ...data, id: String(data.id) } : d)
            }));
        }
    } catch (err) {
        console.error("Add document failed:", err);
    }
  };

  const updateDocument = async (doc: Document) => {
    setState(prev => ({
      ...prev,
      documents: prev.documents.map(d => String(d.id) === String(doc.id) ? doc : d)
    }));
    await supabase.from('documents').update(doc).eq('id', doc.id);
  };

  const updateDocumentStatus = async (id: string, status: 'Draft' | 'Sent' | 'Paid' | 'Expired') => {
      const doc = state.documents.find(d => String(d.id) === String(id));
      if (!doc) return;

      let newTransaction: Transaction | null = null;
      if (doc.type === DocumentType.INVOICE && status === 'Paid' && doc.status !== 'Paid') {
          const subtotal = doc.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
          const taxAmount = (subtotal * state.business.taxPercentage) / 100;
          const total = subtotal + taxAmount;

          newTransaction = {
              id: `sale-inv-${doc.id}-${Date.now()}`,
              type: TransactionType.SALE,
              date: new Date().toISOString().split('T')[0],
              category: 'Product Sales',
              amount: total,
              description: `Payment for Invoice ${doc.number}`,
              reference: doc.number
          };
      }

      setState(prev => ({
          ...prev,
          documents: prev.documents.map(d => String(d.id) === String(id) ? { ...d, status } : d),
          transactions: newTransaction ? [newTransaction, ...prev.transactions] : prev.transactions
      }));

      await supabase.from('documents').update({ status }).eq('id', id);
      if (newTransaction) {
          const { id: txId, ...txData } = newTransaction;
          await supabase.from('transactions').insert(txData);
      }
  };

  const deleteDocument = async (id: string) => {
    setState(prev => ({ ...prev, documents: prev.documents.filter(d => String(d.id) !== String(id)) }));
    await supabase.from('documents').delete().eq('id', id);
  };

  const addTransaction = async (tx: Transaction) => {
    const tempId = tx.id;
    setState(prev => ({ ...prev, transactions: [tx, ...prev.transactions] }));
    const { id, ...txData } = tx;
    const { data } = await supabase.from('transactions').insert(txData).select().single();
    if (data) {
        setState(prev => ({
            ...prev,
            transactions: prev.transactions.map(t => String(t.id) === String(tempId) ? { ...data, id: String(data.id) } : t)
        }));
    }
  };

  const deleteTransaction = async (id: string) => {
    setState(prev => ({ ...prev, transactions: prev.transactions.filter(t => String(t.id) !== String(id)) }));
    await supabase.from('transactions').delete().eq('id', id);
  };

  const addCatalogItem = async (item: CatalogItem) => {
    const tempId = item.id;
    setState(prev => ({ ...prev, catalog: [item, ...prev.catalog] }));
    const { id, ...itemData } = item;
    const { data } = await supabase.from('catalog_items').insert(itemData).select().single();
    if (data) {
        setState(prev => ({
            ...prev,
            catalog: prev.catalog.map(i => String(i.id) === String(tempId) ? { ...data, id: String(data.id) } : i)
        }));
    }
  };

  const updateCatalogItem = async (item: CatalogItem) => {
    setState(prev => ({
      ...prev,
      catalog: prev.catalog.map(i => String(i.id) === String(item.id) ? item : i)
    }));
    await supabase.from('catalog_items').update(item).eq('id', item.id);
  };

  const deleteCatalogItem = async (id: string) => {
    setState(prev => ({ ...prev, catalog: prev.catalog.filter(i => String(i.id) !== String(id)) }));
    await supabase.from('catalog_items').delete().eq('id', id);
  };

  const addClient = async (client: Client) => {
    const tempId = client.id;
    setState(prev => ({ ...prev, clients: [client, ...prev.clients] }));
    const { id, ...clientData } = client;
    const { data } = await supabase.from('clients').insert(clientData).select().single();
    if (data) {
        setState(prev => ({
            ...prev,
            clients: prev.clients.map(c => String(c.id) === String(tempId) ? { ...data, id: String(data.id) } : c)
        }));
    }
  };

  const addClients = async (newClients: Client[]) => {
    setState(prev => ({ ...prev, clients: [...newClients, ...prev.clients] }));
    const formattedClients = newClients.map(({id, ...rest}) => rest);
    await supabase.from('clients').insert(formattedClients);
  };

  const updateClient = async (client: Client) => {
    setState(prev => ({
      ...prev,
      clients: prev.clients.map(c => String(c.id) === String(client.id) ? client : c)
    }));
    await supabase.from('clients').update(client).eq('id', client.id);
  };

  const deleteClient = async (id: string) => {
    setState(prev => ({ ...prev, clients: prev.clients.filter(c => String(c.id) !== String(id)) }));
    await supabase.from('clients').delete().eq('id', id);
  };

  const addUser = async (user: User) => {
    try {
      const { id: _, ...userData } = user;
      const { data, error } = await supabase.from('users').insert({ ...userData, isEnabled: userData.isEnabled ?? true }).select().single();

      if (error) throw error;

      if (data) {
          const newUser = { ...data, id: String(data.id), isEnabled: data.isEnabled ?? true } as User;
          setState(prev => ({ ...prev, users: [newUser, ...prev.users] }));
          return true;
      }
    } catch (err: any) {
      console.error("Supabase User Creation Error:", err.message);
      throw err;
    }
    return false;
  };

  const updateUser = async (user: User) => {
    try {
      const { id, ...userData } = user;
      const { error } = await supabase.from('users').update(userData).eq('id', id);

      if (error) throw error;

      setState(prev => ({
        ...prev,
        users: prev.users.map(u => String(u.id) === String(id) ? user : u)
      }));
      return true;
    } catch (err: any) {
      console.error("Supabase User Update Error:", err.message);
      throw err;
    }
  };

  const deleteUser = async (id: string) => {
    try {
      // Robust deletion from state first for immediate UI feedback
      setState(prev => ({ ...prev, users: prev.users.filter(u => String(u.id) !== String(id)) }));

      // Ensure the ID is correctly parsed for the DB query if it's an integer column
      const dbId = isNaN(Number(id)) ? id : Number(id);
      const { error } = await supabase.from('users').delete().eq('id', dbId);

      if (error) {
        console.error("Supabase deletion error:", error);
        // Re-fetch users if deletion failed to restore state
        const { data } = await supabase.from('users').select('*').order('created_at', { ascending: false });
        if (data) {
            setState(prev => ({ ...prev, users: data.map(u => ({ ...u, id: String(u.id) })) }));
        }
      }
    } catch (err) {
      console.error("User deletion error:", err);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-500 font-bold animate-pulse">Synchronizing Ledger System...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return <Login users={state.users} onLogin={handleLogin} poweredBy={state.business.poweredByText} />;
  }

  return (
    <HashRouter>
      <div className="flex flex-col md:flex-row min-h-screen bg-slate-50 text-slate-900 font-sans selection:bg-blue-100 selection:text-blue-900">
        <Sidebar 
          isOpen={isSidebarOpen} 
          setIsOpen={setIsSidebarOpen} 
          business={state.business} 
          currentUser={currentUser} 
          onLogout={handleLogout}
        />

        <main className="flex-1 flex flex-col h-screen overflow-hidden">
          <header className="md:hidden flex items-center justify-between p-6 bg-white border-b border-slate-100 shrink-0">
             <div className="flex items-center gap-3">
               <div className="bg-blue-600 w-8 h-8 rounded-lg flex items-center justify-center shadow-lg shadow-blue-500/20">
                 <i className="fa-solid fa-bolt text-white text-sm"></i>
               </div>
               <h1 className="text-lg font-black tracking-tight">Invoice ME</h1>
             </div>
             <button onClick={() => setIsSidebarOpen(true)} className="p-2 text-slate-500 hover:text-slate-900 transition-colors">
               <i className="fa-solid fa-bars-staggered text-xl"></i>
             </button>
          </header>

          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 md:p-10 lg:p-12">
            <Routes>
              <Route path="/" element={<Dashboard state={state} />} />
              <Route path="/quotations" element={
                <DocumentManager 
                  type={DocumentType.QUOTATION} 
                  state={state} 
                  addDocument={addDocument} 
                  updateDocument={updateDocument} 
                  deleteDocument={deleteDocument} 
                  updateStatus={updateDocumentStatus}
                  addClient={addClient}
                />
              } />
              <Route path="/invoices" element={
                <DocumentManager 
                  type={DocumentType.INVOICE} 
                  state={state} 
                  addDocument={addDocument} 
                  updateDocument={updateDocument} 
                  deleteDocument={deleteDocument} 
                  updateStatus={updateDocumentStatus}
                  addClient={addClient}
                />
              } />
              <Route path="/clients" element={
                <ClientManager 
                  state={state} 
                  addClient={addClient} 
                  addClients={addClients}
                  updateClient={updateClient} 
                  deleteClient={deleteClient} 
                />
              } />
              <Route path="/catalog" element={
                <CatalogManager 
                  state={state} 
                  addItem={addCatalogItem} 
                  updateItem={updateCatalogItem} 
                  deleteItem={deleteCatalogItem} 
                />
              } />
              <Route path="/sales" element={
                <TransactionManager 
                  type={TransactionType.SALE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction} 
                />
              } />
              <Route path="/expenses" element={
                <TransactionManager 
                  type={TransactionType.EXPENSE} 
                  state={state} 
                  addTransaction={addTransaction} 
                  deleteTransaction={deleteTransaction} 
                />
              } />
              <Route path="/users" element={
                currentUser.role === 'admin' ? (
