import React, { useState, useRef } from 'react';
import { BusinessDetails } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  business: BusinessDetails;
  updateBusiness: (details: BusinessDetails) => void;
}

const CURRENCIES = [
    { code: 'MVR', symbol: 'Rf', name: 'Maldivian Rufiyaa' },
    { code: 'USD', symbol: '$', name: 'US Dollar' },
    { code: 'EUR', symbol: '€', name: 'Euro' },
    { code: 'GBP', symbol: '£', name: 'British Pound' },
    { code: 'INR', symbol: '₹', name: 'Indian Rupee' },
    { code: 'AED', symbol: 'DH', name: 'UAE Dirham' }
];

const Settings: React.FC<Props> = ({ business, updateBusiness }) => {
  const [details, setDetails] = useState<BusinessDetails>(business);
  const [isSaved, setIsSaved] = useState(false);
  const [isGeneratingTerms, setIsGeneratingTerms] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const paymentRef = useRef<HTMLTextAreaElement>(null);
  const termsRef = useRef<HTMLTextAreaElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateBusiness(details);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleLogoClick = () => {
    fileInputRef.current?.click();
  };

  const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setDetails(prev => ({ ...prev, logoUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const removeLogo = (e: React.MouseEvent) => {
    e.stopPropagation();
    setDetails(prev => ({ ...prev, logoUrl: undefined }));
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleFormat = (field: 'paymentDetails' | 'defaultTerms', type: 'bold' | 'italic' | 'list') => {
    const ref = field === 'paymentDetails' ? paymentRef : termsRef;
    if (!ref.current) return;

    const start = ref.current.selectionStart;
    const end = ref.current.selectionEnd;
    const text = details[field] || '';
    const selected = text.substring(start, end);

    let formatted = '';
    if (type === 'bold') formatted = `**${selected || 'bold text'}**`;
    else if (type === 'italic') formatted = `*${selected || 'italic text'}*`;
    else if (type === 'list') formatted = `\n- ${selected || 'list item'}`;

    const newVal = text.substring(0, start) + formatted + text.substring(end);
    setDetails({ ...details, [field]: newVal });

    // Refocus after state update
    setTimeout(() => {
      ref.current?.focus();
      ref.current?.setSelectionRange(start + 2, start + 2 + (selected.length || formatted.length - 4));
    }, 0);
  };

  const handleGenerateTerms = async () => {
    setIsGeneratingTerms(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Generate a modern, professional, and concise set of "Terms and Conditions" for a business named "${details.name || 'our company'}". 
      The terms should be formatted as a numbered list and include:
      1. Payment deadlines.
      2. Quote validity period.
      3. Brief note on cancellations or returns.
      4. Late payment interest note.
      Keep it under 150 words and sounding very professional. Use **bold** for key terms.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });

      const generatedText = response.text;
      if (generatedText) {
        setDetails(prev => ({ ...prev, defaultTerms: generatedText.trim() }));
      }
    } catch (error) {
      console.error("Failed to generate terms:", error);
    } finally {
      setIsGeneratingTerms(false);
    }
  };

  const FormatToolbar = ({ field }: { field: 'paymentDetails' | 'defaultTerms' }) => (
    <div className="flex gap-2 mb-2">
      <button type="button" onClick={() => handleFormat(field, 'bold')} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 transition-colors" title="Bold">
        <i className="fa-solid fa-bold text-xs"></i>
      </button>
      <button type="button" onClick={() => handleFormat(field, 'italic')} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 transition-colors" title="Italic">
        <i className="fa-solid fa-italic text-xs"></i>
      </button>
      <button type="button" onClick={() => handleFormat(field, 'list')} className="w-8 h-8 flex items-center justify-center rounded-lg bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 transition-colors" title="List Item">
        <i className="fa-solid fa-list-ul text-xs"></i>
      </button>
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto space-y-6 md:space-y-8 animate-fadeIn pb-12">
      <header>
        <h1 className="text-2xl md:text-3xl font-bold text-slate-900">Settings</h1>
        <p className="text-sm text-slate-500">Configure your company identity and regional preferences.</p>
      </header>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 md:p-8 border-b border-slate-100 bg-slate-50/50">
            <div className="flex flex-col sm:flex-row items-center gap-6">
                <div 
                  onClick={handleLogoClick}
                  className="group relative w-24 h-24 rounded-2xl bg-slate-200 flex items-center justify-center border-4 border-white shadow-sm overflow-hidden cursor-pointer hover:bg-slate-300 transition-all shrink-0"
                >
                    {details.logoUrl ? (
                      <img src={details.logoUrl} className="w-full h-full object-cover" alt="Business Logo" />
                    ) : (
                      <i className="fa-solid fa-building text-4xl text-slate-400"></i>
                    )}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                      <i className="fa-solid fa-camera text-white text-xl"></i>
                    </div>
                </div>

                <input 
                  type="file" 
                  ref={fileInputRef} 
                  className="hidden" 
                  accept="image/*"
                  onChange={handleLogoChange}
                />

                <div className="text-center sm:text-left">
                    <h2 className="text-xl font-bold text-slate-800 truncate max-w-[250px] md:max-w-md">{details.name || 'Your Company Name'}</h2>
                    <p className="text-slate-500 text-sm">Update your logo and business information</p>
                    <div className="flex justify-center sm:justify-start gap-4 mt-3">
                      <button 
                        type="button" 
                        onClick={handleLogoClick}
                        className="text-blue-600 text-xs font-semibold hover:underline flex items-center gap-1"
                      >
                        <i className="fa-solid fa-upload"></i>
                        Change Logo
                      </button>
                      {details.logoUrl && (
                        <button 
                          type="button" 
                          onClick={removeLogo}
                          className="text-red-500 text-xs font-semibold hover:underline flex items-center gap-1"
                        >
                          <i className="fa-solid fa-trash-can"></i>
                          Remove
                        </button>
                      )}
                    </div>
                </div>
            </div>
        </div>

        <form onSubmit={handleSubmit} className="p-6 md:p-8 space-y-10">
          <section className="space-y-6">
            <h3 className="text-base md:text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Business Identity</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5 md:gap-6">
                <div className="col-span-1 md:col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Company Name</label>
                <input 
                    required
                    value={details.name}
                    onChange={(e) => setDetails({...details, name: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Business Email</label>
                <input 
                    required
                    type="email"
                    value={details.email}
                    onChange={(e) => setDetails({...details, email: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Phone Number</label>
                <input 
                    required
                    value={details.phone}
                    onChange={(e) => setDetails({...details, phone: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div className="col-span-1 md:col-span-2">
                <label className="block text-sm font-semibold text-slate-700 mb-2">Physical Address</label>
                <input 
                    required
                    value={details.address}
                    onChange={(e) => setDetails({...details, address: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                />
                </div>
                <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">TIN Number</label>
                <input 
                    required
                    value={details.tinNumber}
                    onChange={(e) => setDetails({...details, tinNumber: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                    placeholder="Tax Identification Number"
                />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Sidebar Footer Text (Powered by)</label>
                  <input 
                      value={details.poweredByText || ''}
                      onChange={(e) => setDetails({...details, poweredByText: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-emerald-500 text-slate-900 text-sm"
                      placeholder="e.g. SANDPIX MALDIVES"
                  />
                </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-base md:text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Regional & Tax Settings</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-5 md:gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Default GST/Tax Percentage (%)</label>
                  <div className="relative">
                    <input 
                        required
                        type="number"
                        step="0.01"
                        value={details.taxPercentage}
                        onChange={(e) => setDetails({...details, taxPercentage: parseFloat(e.target.value) || 0})}
                        className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                        placeholder="e.g. 8"
                    />
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">%</div>
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Business Currency</label>
                  <select 
                      required
                      value={details.currency}
                      onChange={(e) => setDetails({...details, currency: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm appearance-none"
                  >
                    {CURRENCIES.map(curr => (
                      <option key={curr.code} value={curr.code}>{curr.code} ({curr.symbol}) - {curr.name}</option>
                    ))}
                  </select>
                </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-base md:text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Document Numbering</h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-5 md:gap-6">
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Invoice Prefix</label>
                  <input 
                      required
                      value={details.invoicePrefix}
                      onChange={(e) => setDetails({...details, invoicePrefix: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                      placeholder="e.g. INV"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-slate-700 mb-2">Quotation Prefix</label>
                  <input 
                      required
                      value={details.quotationPrefix}
                      onChange={(e) => setDetails({...details, quotationPrefix: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm"
                      placeholder="e.g. QT"
                  />
                </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-base md:text-lg font-bold text-slate-800 border-l-4 border-blue-600 pl-4">Payment & Terms</h3>
            <div className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Payment Details (Bank Info)</label>
                <FormatToolbar field="paymentDetails" />
                <textarea 
                    ref={paymentRef}
                    value={details.paymentDetails}
                    onChange={(e) => setDetails({...details, paymentDetails: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm min-h-[80px]"
                    placeholder="Bank account name, number, etc..."
                />
              </div>
              <div>
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 mb-2">
                    <label className="block text-sm font-semibold text-slate-700">Default Terms & Conditions</label>
                    <button 
                        type="button" 
                        disabled={isGeneratingTerms}
                        onClick={handleGenerateTerms}
                        className="text-blue-600 text-xs font-bold hover:underline flex items-center gap-1 bg-blue-50 px-3 py-2 rounded-lg transition-colors disabled:opacity-50"
                    >
                        <i className={`fa-solid ${isGeneratingTerms ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                        {isGeneratingTerms ? 'Processing...' : 'AI Suggest Terms'}
                    </button>
                </div>
                <FormatToolbar field="defaultTerms" />
                <textarea 
                    ref={termsRef}
                    value={details.defaultTerms}
                    onChange={(e) => setDetails({...details, defaultTerms: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500 text-slate-900 text-sm min-h-[120px]"
                    placeholder="Enter standard terms..."
                />
              </div>
            </div>
          </section>

          <div className="flex flex-col sm:flex-row items-center justify-between gap-6 pt-8 border-t border-slate-100">
            {isSaved ? (
                <span className="text-emerald-600 text-sm font-medium flex items-center gap-2">
                    <i className="fa-solid fa-check-circle"></i> Profile updated successfully!
                </span>
            ) : <span className="text-slate-400 text-xs italic text-center sm:text-left">Ensure all fields are accurate for legal documents</span>}
            <button 
              type="submit"
              className="w-full sm:w-auto px-10 py-3.5 bg-slate-900 text-white rounded-xl font-bold shadow-xl shadow-slate-200 hover:bg-black transition-all"
            >
              Save Changes
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default Settings;

import React, { useState, useMemo, useRef } from 'react';
import { Link } from 'react-router-dom';
import { AppState, Document, DocumentType, LineItem, CatalogItem, Client } from '../types';
import { generatePDF } from '../utils/pdfGenerator';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  type: DocumentType;
  state: AppState;
  addDocument: (doc: Document) => void;
  updateDocument: (doc: Document) => void;
  deleteDocument: (id: string) => void;
  updateStatus: (id: string, status: any) => void;
  addClient: (client: Client) => void;
}

const DocumentManager: React.FC<Props> = ({ type, state, addDocument, updateDocument, deleteDocument, updateStatus, addClient }) => {
  const [showModal, setShowModal] = useState(false);
  const [showCatalogModal, setShowCatalogModal] = useState(false);
  const [showClientModal, setShowClientModal] = useState(false);
  const [catalogSearchTerm, setCatalogSearchTerm] = useState('');
  const [clientSearchTerm, setClientSearchTerm] = useState('');
  const [loadingSmart, setLoadingSmart] = useState(false);
  const [editingDocId, setEditingDocId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [saveClientStatus, setSaveClientStatus] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const notesRef = useRef<HTMLTextAreaElement>(null);

  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    date: new Date().toISOString().split('T')[0],
    dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    notes: state.business.defaultTerms || '',
    items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }] as LineItem[]
  });

  const filteredDocs = useMemo(() => {
    const docs = state.documents.filter(d => d.type === type);
    if (!searchTerm.trim()) return docs;

    const term = searchTerm.toLowerCase();
    return docs.filter(d => 
      d.number.toLowerCase().includes(term) ||
      d.clientName.toLowerCase().includes(term) ||
      (d.clientEmail && d.clientEmail.toLowerCase().includes(term))
    );
  }, [state.documents, type, searchTerm]);

  const filteredCatalog = useMemo(() => {
    if (!catalogSearchTerm.trim()) return state.catalog;
    const term = catalogSearchTerm.toLowerCase();
    return state.catalog.filter(item => 
      item.description.toLowerCase().includes(term)
    );
  }, [state.catalog, catalogSearchTerm]);

  const filteredClients = useMemo(() => {
    if (!clientSearchTerm.trim()) return state.clients;
    const term = clientSearchTerm.toLowerCase();
    return state.clients.filter(c => 
      c.name.toLowerCase().includes(term) || 
      (c.email && c.email.toLowerCase().includes(term))
    );
  }, [state.clients, clientSearchTerm]);

  const currentSubtotal = useMemo(() => {
    return formData.items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  }, [formData.items]);

  const currentTaxAmount = useMemo(() => {
    return (currentSubtotal * state.business.taxPercentage) / 100;
  }, [currentSubtotal, state.business.taxPercentage]);

  const currentTotal = currentSubtotal + currentTaxAmount;

  const formatDateDisplay = (dateStr: string) => {
    if (!dateStr) return '';
    return dateStr.split('-').reverse().join('-');
  };

  const resetForm = () => {
    setFormData({
      clientName: '',
      clientEmail: '',
      date: new Date().toISOString().split('T')[0],
      dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      notes: state.business.defaultTerms || '',
      items: [{ id: '1', description: '', quantity: 1, unitPrice: 0 }]
    });
    setEditingDocId(null);
    setShowModal(false);
    setSaveClientStatus(null);
  };

  const handleEdit = (doc: Document) => {
    setFormData({
      clientName: doc.clientName,
      clientEmail: doc.clientEmail || '',
      date: doc.date,
      dueDate: doc.dueDate,
      notes: doc.notes || '',
      items: doc.items.map(item => ({ ...item }))
    });
    setEditingDocId(doc.id);
    setShowModal(true);
    setSaveClientStatus(null);
  };

  const handleAddItem = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), description: '', quantity: 1, unitPrice: 0 }]
    }));
  };

  const handleAddFromCatalog = (catalogItem: CatalogItem) => {
    const newItem: LineItem = {
      id: Date.now().toString() + Math.random(),
      description: catalogItem.description,
      quantity: 1,
      unitPrice: catalogItem.unitPrice
    };

    setFormData(prev => {
      if (prev.items.length === 1 && !prev.items[0].description && prev.items[0].unitPrice === 0) {
        return { ...prev, items: [newItem] };
      }
      return { ...prev, items: [...prev.items, newItem] };
    });
    setShowCatalogModal(false);
    setCatalogSearchTerm('');
  };

  const handleSelectClient = (client: Client) => {
    setFormData(prev => ({
      ...prev,
      clientName: client.name,
      clientEmail: client.email || ''
    }));
    setShowClientModal(false);
    setClientSearchTerm('');
  };

  const handleFormat = (type: 'bold' | 'italic' | 'list') => {
    if (!notesRef.current) return;
    const start = notesRef.current.selectionStart;
    const end = notesRef.current.selectionEnd;
    const text = formData.notes || '';
    const selected = text.substring(start, end);

    let formatted = '';
    if (type === 'bold') formatted = `**${selected || 'bold text'}**`;
    else if (type === 'italic') formatted = `*${selected || 'italic text'}*`;
    else if (type === 'list') formatted = `\n- ${selected || 'list item'}`;

    const newVal = text.substring(0, start) + formatted + text.substring(end);
    setFormData({ ...formData, notes: newVal });

    setTimeout(() => {
      notesRef.current?.focus();
      notesRef.current?.setSelectionRange(start + 2, start + 2 + (selected.length || formatted.length - 4));
    }, 0);
  };

  const handleSaveToPredefined = () => {
    if (!formData.clientName.trim()) {
      setSaveClientStatus({ type: 'error', message: 'Name is required.' });
      return;
    }
    const isDuplicate = state.clients.some(c => 
      c.name.toLowerCase() === formData.clientName.toLowerCase() || 
      (formData.clientEmail.trim() !== '' && c.email?.toLowerCase() === formData.clientEmail.toLowerCase())
    );
    if (isDuplicate) {
      setSaveClientStatus({ type: 'error', message: 'Client already exists.' });
    } else {
      addClient({
        id: `manual-${Date.now()}`,
        name: formData.clientName,
        email: formData.clientEmail || undefined,
        phone: '',
        address: ''
      });
      setSaveClientStatus({ type: 'success', message: 'Client saved!' });
    }
    setTimeout(() => setSaveClientStatus(null), 3000);
  };

  const handleRemoveItem = (id: string) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleItemChange = (id: string, field: keyof LineItem, value: any) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingDocId) {
      const existingDoc = state.documents.find(d => String(d.id) === String(editingDocId));
      if (existingDoc) {
        const updatedDoc: Document = {
          ...existingDoc,
          clientName: formData.clientName,
          clientEmail: formData.clientEmail || undefined,
          date: formData.date,
          dueDate: formData.dueDate,
          items: formData.items,
          notes: formData.notes
        };
        updateDocument(updatedDoc);
      }
    } else {
      const prefix = type === DocumentType.QUOTATION ? state.business.quotationPrefix : state.business.invoicePrefix;
      const newDoc: Document = {
        id: Date.now().toString(),
        type,
        number: `${prefix}-${Math.floor(1000 + Math.random() * 9000)}`,
        clientName: formData.clientName,
        clientEmail: formData.clientEmail || undefined,
        date: formData.date,
        dueDate: formData.dueDate,
        items: formData.items,
        status: 'Draft',
        notes: formData.notes
      };
      addDocument(newDoc);
    }
    resetForm();
  };

  const handleSmartGenerate = async () => {
    setLoadingSmart(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Generate 3 professional service line items for a business in the ${state.business.name} industry. Return as JSON array of objects with description (string) and unitPrice (number).`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { 
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            description: { type: Type.STRING },
                            unitPrice: { type: Type.NUMBER }
                        },
                        required: ['description', 'unitPrice']
                    }
                }
            }
        });
        const items = JSON.parse(response.text || '[]');
        setFormData(prev => ({
            ...prev,
            items: items.map((it: any, idx: number) => ({
                id: `smart-${idx}-${Date.now()}`,
                description: it.description,
                quantity: 1,
                unitPrice: it.unitPrice
            }))
        }));
    } catch (err) {
        console.error("AI Error:", err);
    } finally {
        setLoadingSmart(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Paid': return 'bg-emerald-100 text-emerald-700 border-emerald-200';
      case 'Sent': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'Expired': return 'bg-rose-100 text-rose-700 border-rose-200';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  const getDocTypeIcon = () => type === DocumentType.QUOTATION ? 'fa-file-lines' : 'fa-file-invoice-dollar';

  return (
    <div className="space-y-8 animate-fadeIn pb-12">
      {/* Header Section */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <div className={`p-2 rounded-xl text-white ${type === DocumentType.QUOTATION ? 'bg-indigo-500' : 'bg-blue-600'}`}>
              <i className={`fa-solid ${getDocTypeIcon()} text-lg`}></i>
            </div>
            <h1 className="text-2xl md:text-3xl font-black text-slate-900 tracking-tight">
              {type === DocumentType.QUOTATION ? 'Quotations' : 'Invoices'}
            </h1>
          </div>
          <p className="text-slate-500">Track and manage your {type === DocumentType.QUOTATION ? 'pricing quotes' : 'billing documents'} with ease.</p>
        </div>

        <div className="flex flex-col sm:flex-row w-full lg:w-auto items-stretch sm:items-center gap-3">
          <div className="relative flex-1 lg:w-72">
            <i className="fa-solid fa-magnifying-glass absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"></i>
            <input 
              type="text"
              placeholder={`Search ${type.toLowerCase()}s...`}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
